INSERT INTO `pcta_options` VALUES (8256,'_transient_feed_d117b5738fbd35bd8c0391cda1f2b5d9','a:4:{s:5:\"child\";a:1:{s:0:\"\";a:1:{s:3:\"rss\";a:1:{i:0;a:6:{s:4:\"data\";s:3:\"\n\n\n\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:7:\"version\";s:3:\"2.0\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:1:{s:0:\"\";a:1:{s:7:\"channel\";a:1:{i:0;a:6:{s:4:\"data\";s:61:\"\n	\n	\n	\n	\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:1:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"WordPress Planet\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://planet.wordpress.org/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"language\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"en\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:47:\"WordPress Planet - http://planet.wordpress.org/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"item\";a:50:{i:0;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:93:\"WordCamp Central: SiteGround joins the WordPress global community sponsorship program in 2023\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:39:\"https://central.wordcamp.org/?p=3165350\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:118:\"https://central.wordcamp.org/news/2023/05/siteground-joins-the-wordpress-global-community-sponsorship-program-in-2023/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2491:\"<p>Please join us in welcoming <a href=\"https://siteground.com/wordpress-hosting.htm\">SiteGround</a> to the&nbsp;<a href=\"https://central.wordcamp.org/sponsor-multiple-wordcamps/\">2023 WordPress global community sponsorship program</a>! SiteGroundâs pledge to sponsor all official WordPress community events (WordCamps, Meetups, and more) all around the world provides support and stability to our hardworking crew of volunteer event organizers. Thanks for everything, SiteGround!</p>\n\n\n<div class=\"wp-block-image\">\n<a href=\"https://central.wordcamp.org/files/2023/05/siteground-logo-black-transparent-400x81-2.png\"><img /></a></div>\n\n\n<p><a href=\"https://siteground.com/wordpress-hosting.htm\">SiteGround</a>&#8216;s hosting services are crafted to make managing websites easy, whether you&#8217;re building a site for yourself, your small business, or your clients.</p>\n\n\n\n<p>We host over 2.8 Million domain names on a powerful Google Cloud Platform infrastructure, optimized with an array of in-house tools for seamless, faster and more secure WordPress performance:</p>\n\n\n\n<p></p>\n\n\n\n<ul>\n<li>Fast: Choose from multiple data centers across USA, Europe, Asia, and Australia, complemented by over 170 CDN edge network locations with our free CDN to improve website performance. Powerful built-in Caching, custom PHP setup, and SiteGround Optimizer plugin for WordPress to make your sites up to 5 times faster right out of the box.</li>\n\n\n\n<li>Secure: Advanced security on server, website, and application level with a free SSL, advanced built-in Web Application Firewall, SiteGround Security plugin, in-house antispam protection and AI-powered anti-bot system to keep your websites safe.</li>\n\n\n\n<li>Easy to manage: Build or transfer WordPress projects in a few clicks with our WordPress Starter and Automatic website and Email Migrators. Manage multiple sites in one place hassle-free, get automatic core and plugin updates, add team collaborators, ship sites to clients, manage white-label hosting, and many more handy features to keep all the control, but spare you the hassle of website management.</li>\n</ul>\n\n\n\n<p>Our long-term expertise in helping WordPress users succeed online extends into our award-winning <a href=\"https://www.siteground.com/wordpress-plugins/siteground-optimizer\">SiteGround Optimizer</a> and <a href=\"https://www.siteground.com/wordpress-plugins/siteground-security\">SiteGround Security</a>; plugins, free to download and install on any hosting platform.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 22 May 2023 16:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"Isotta\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:84:\"WordPress.org blog: WP Briefing: Episode 56: What to Know About WordPress Playground\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"https://wordpress.org/news/?post_type=podcast&p=14968\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:86:\"https://wordpress.org/news/2023/05/episode-56-what-to-know-about-wordpress-playground/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:16989:\"<p>Join guest host Rich Tabor and WordPress Playground innovator Adam Zielinski as they discuss the capabilities and promise of WP Playground in episode 56 of the WordPress Briefing. Stay tuned for your small list of big things coming up in the next two weeks.</p>\n\n\n\n<p><em><strong>Have a question youâd like answered? You can submit them to&nbsp;<a href=\"mailto:wpbriefing@wordpress.org\">wpbriefing@wordpress.org</a>, either written or as a voice recording.</strong></em></p>\n\n\n\n<h2 class=\"wp-block-heading\">Credits</h2>\n\n\n\n<p>Host: <a href=\"https://profiles.wordpress.org/chanthaboune/\">Josepha Haden Chomphosy</a><br />Guests: <a href=\"https://profiles.wordpress.org/richtabor/\">Rich Tabor</a> and <a href=\"https://profiles.wordpress.org/zieladam/\">Adam Zielinski</a><br />Editor:&nbsp;<a href=\"https://profiles.wordpress.org/dustinhartzler/\">Dustin Hartzler</a><br />Logo:&nbsp;<a href=\"https://profiles.wordpress.org/javiarce/\">Javier Arce</a><br />Production:&nbsp;<a href=\"https://profiles.wordpress.org/bjmcsherry/\">Brett McSherry</a> and <a href=\"https://profiles.wordpress.org/eidolonnight/\">Nicholas Garofalo</a><br />Song: Fearless First by Kevin MacLeod</p>\n\n\n\n<h2 class=\"wp-block-heading\">Show Notes</h2>\n\n\n\n<ul>\n<li><a href=\"https://developer.wordpress.org/playground/\">WordPress Playground</a> and the <a href=\"https://github.com/WordPress/wordpress-playground\">Playground Github repo</a></li>\n\n\n\n<li><a href=\"https://gliwice.wordcamp.org/2023/\">WordCamp Gliwice</a> </li>\n\n\n\n<li><a href=\"https://europe.wordcamp.org/2023/\">WordCamp Europe 2023</a>, <a href=\"https://europe.wordcamp.org/2023/contributor-day/\">Contributor Day,</a> and <a href=\"https://europe.wordcamp.org/2023/presenting-wp-connect/\">WP Connect</a></li>\n\n\n\n<li><a href=\"https://wordpress.slack.com/archives/C04EWKGDJ0K\">#meta-playground</a> in the <a href=\"https://make.wordpress.org/chat/\">Making WordPress Slack</a></li>\n\n\n\n<li><a href=\"https://chat.openai.com/\">ChatGPT</a></li>\n\n\n\n<li><a href=\"https://woocommerce.com/\">WooCommerce</a></li>\n\n\n\n<li><a href=\"https://www.cloudfest.com/\">CloudFest</a> and <a href=\"https://profiles.wordpress.org/danielbachhuber/\">Daniel Bachhuber</a></li>\n\n\n\n<li>The <a href=\"https://wordpress.org/news/feed/blank\">Kim Parsell Memorial Scholarship</a> for travel to WordCamp US 2023</li>\n\n\n\n<li>Find your closest location for a <a href=\"https://wp20.wordpress.net/\">WordPress 20th Anniversary celebration</a></li>\n\n\n\n<li><a href=\"https://us.wordcamp.org/2023/wordcamp-us-2023-programming-team-announcement/\">Changes to the WCUS event for 2023</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Transcript</h2>\n\n\n\n<span id=\"more-14968\"></span>\n\n\n\n<p><strong>[Josepha Haden Chomphosy 00:00:00]</strong></p>\n\n\n\n<p>(Intro music)</p>\n\n\n\n<p>Hello everyone, and welcome to the WordPress Briefing, the podcast where you can catch quick explanations of the ideas behind the WordPress Open Source project, some insight into the community that supports it, and get a small list of big things coming up in the next two weeks. I&#8217;m your host, Josepha Haden Chomphosy. Here we go.</p>\n\n\n\n<p>(Intro continues)</p>\n\n\n\n<p><strong>[Josepha Haden Chomphosy 00:00:40]</strong></p>\n\n\n\n<p>Today we&#8217;re gonna spend a little time talking about WP Playground. This is a project that debuted at State of the Word in December 2022, but it was demoed for me about a month prior in November.</p>\n\n\n\n<p>I was, and remain, absolutely floored by the potential future applications, as well as the innovative thinking behind it. So I&#8217;ve invited a couple of excellent WordPress futurists to the show today so that we can listen in on their conversation.</p>\n\n\n\n<p>Welcome guys.</p>\n\n\n\n<p><strong>[Rich Tabor 00:01:07]</strong></p>\n\n\n\n<p>Hey everyone, I&#8217;m Rich Tabor, and I&#8217;m here today with Adam Zielinski to talk about WordPress Playground. So for those of you who don&#8217;t know what WordPress Playground is, can you tell us a little bit more about it, Adam?</p>\n\n\n\n<p><strong>[Adam Zielinski 00:01:18]</strong></p>\n\n\n\n<p>Absolutely. WordPress Playground is WordPress that works in your browser like there&#8217;s no server with PHP or database like there&#8217;s just your browser and JavaScript, and you can run it in so many more places that weâll all get to. For example, I just came back from WordCamp Gliwice, where on a Contributor Day, a couple of developers got set up with WordPress in just a couple of minutes, whereas normally, it can take hours to do that.</p>\n\n\n\n<p><strong>[Rich Tabor 00:01:44]</strong></p>\n\n\n\n<p>Yeah, that&#8217;s, that&#8217;s pretty impressive. Do you think that, particularly for WordCamps and other demo-type areas, this would be something that&#8217;s very useful? Or what do you think would be the other problems that could be solved with WordPress Playground?</p>\n\n\n\n<p><strong>[Adam Zielinski 00:01:55]</strong></p>\n\n\n\n<p>Playground solves one primary problem, and that is WordPress is pretty difficult to get started with. I&#8217;m not even talking about creating your website, but let&#8217;s say, someone told you there&#8217;s this WordPress thing that you should try. Well, you Google for it, and you find installation instructions, and there&#8217;s like three hours of work for you there.</p>\n\n\n\n<p>So then maybe you&#8217;ll find a hosting company, and you have to pay some money. So with WordPress Playground, you can actually try it for free because there&#8217;s no cost to run it. It just runs on your device. If you&#8217;re a developer, and you want to start learning WordPress, normally you have to go through quite an extensive setup process, and there are some tools to make it easier, but maybe there&#8217;s still friction like you have to even own a computer, like a PC device or a Mac. Playground can run on your phone, and it can power interactive tutorials that you can use and just start learning there and there with zero setup.</p>\n\n\n\n<p>Like if you work on a product team and someone asks you to test a code change, with Playground you can just click a link and test it with no infrastructure behind it. And if you&#8217;re a company creating a plugin, you can just show your plugin in a live demo to people. And this isn&#8217;t something many plugins are doing because it&#8217;s quite hard to get a live demo set up.</p>\n\n\n\n<p><strong>[Rich Tabor 00:03:12]</strong></p>\n\n\n\n<p>Ah, that&#8217;s pretty impressive. So, you know, amongst like tutorials, code changes for developer environments, the mobile application running, do you think that, since there&#8217;s such a wide brevity of ideas that WordPress Playground can kind of plug into, would this be more of a developer tool?</p>\n\n\n\n<p>Is that right? Or is Playground more of a like a click and play-type application that can run anywhere and demo anything?</p>\n\n\n\n<p><strong>[Adam Zielinski 00:03:36]</strong></p>\n\n\n\n<p>I&#8217;d say it&#8217;s both, but it&#8217;s more transparent for the users. So there are a whole lot of things you can do with Playground as a developer, as I just mentioned. But who are you doing these things for? Well, some of them are for the users, as in live demos, or there&#8217;s a WordCamp Europe coming, and I know some people are doing workshops there. They are going to use Playground to get everyone set up. So now that&#8217;s, well, maybe a workshop that teaches you how to build a theme, for example, right? Now you can just get started without any setup process. So there&#8217;s both, it&#8217;s very useful for development teams, and it&#8217;s very useful for them to build stuff for the final users.</p>\n\n\n\n<p><strong>[Rich Tabor 00:04:21]</strong></p>\n\n\n\n<p>That&#8217;s great. I know you, and I have probably both been in the same scenario at WordCamps when you&#8217;re trying to get dev environments set up, and it takes, you know, the better half of the workshop to get to step one. So this is really gonna be interesting to see it, especially at WordCamp Europe, and to see it getting into action.</p>\n\n\n\n<p>Are you planning on going to WordCamp Europe this year?</p>\n\n\n\n<p><strong>[Adam Zielinski 00:04:39]</strong></p>\n\n\n\n<p>Absolutely, I will have a table at Contributor Day, a WordPress Playground table. So yeah, everyone&#8217;s invited to come over. I&#8217;ll show you a lot of cool stuff. And then at WP Connect on Saturday at 10:00 AM, there will be a WordPress Playground session where you&#8217;ll be able to learn more and see some cool demos.</p>\n\n\n\n<p>And this will be a conversational format, so we&#8217;ll just have a nice chat.</p>\n\n\n\n<p><strong>[Rich Tabor 00:05:01]</strong></p>\n\n\n\n<p>Super cool. So how else can people find out a little bit more info about Playground and perhaps even get involved and contribute to the project?</p>\n\n\n\n<p><strong>[Adam Zielinski 00:05:08]</strong></p>\n\n\n\n<p>There&#8217;s a developer.WordPress.org/playground website. There&#8217;s a link in a show notes where you&#8217;ll be able, like this is the perfect entry point to the entire rabbit hole of WordPress Playground.</p>\n\n\n\n<p>There&#8217;s a quite a few projects under the WordPress Playground umbrella, and they all live in a single GitHub repository where you can just find any issue that interests if you want to contribute and just start contributing. Also, there&#8217;s a Slack channel in WordPress org space called #meta-playground, and I highly encourage everyone interested in coming over to say hi.</p>\n\n\n\n<p>And probably one of the best places to ask questions and get acquainted with the community.</p>\n\n\n\n<p><strong>[Rich Tabor 00:05:54]</strong></p>\n\n\n\n<p>Oh, that&#8217;s great; I&#8217;m very intrigued about the project overall. I think that there&#8217;s an immense amount of potential, for WordPress Playground. Just last question here, like, where do you see the future of this project going? What is the most interesting application that hasn&#8217;t been done yet, or the things that are really gonna be the next level in unlocking Playground for everyone?</p>\n\n\n\n<p><strong>[Adam Zielinski 00:06:12]</strong></p>\n\n\n\n<p>There&#8217;s quite a few. Imagine being able to go to WordPress.org and have a WordPress demo right then and there without having to download anything. Then you customize it, and you have a button to host your website anywhere or just to download it.</p>\n\n\n\n<p>Imagine having a live preview for all the themes and plugins in the directory and even in WordPress core, but these are sooner than later. Maybe like, let&#8217;s talk more grandiose, shall we? So there&#8217;s this term, 1 billion new users coming online in the next, like in the nearest future, and plenty of them doesn&#8217;t even own a desktop device. Maybe they have a mobile phone, maybe they have a tablet, maybe we&#8217;re talking about a young, prospective developer somewhere. And currently, if you don&#8217;t own a desktop device, you cannot contribute to the WordPress plugin ecosystem at all.</p>\n\n\n\n<p>Like, we&#8217;re seeing more and more of creating themes with no code, which is really exciting. But you cannot build the plugin, really. Well, with WordPress Playground. Suddenly you can do development on a mobile device. So development tools and code editors and just the entire suite of things we use as the developers on our desktop of devices like this may come online and be available in your browser.</p>\n\n\n\n<p>And if you&#8217;re on a train and you just have a phone with you, but you still want to learn, how to build a plugin, well, you&#8217;ll be able to do that. Furthermore, there&#8217;s a lot of exciting opportunities with ChatGPT, as in, well, here&#8217;s a WordPress running entirely on your device. So maybe if that&#8217;s connected to ChatGPT, you&#8217;ll be able to say, well, I like fish, or like, I want two columns and a photo of a racing car on top of it.</p>\n\n\n\n<p>And because ChatGPT can output HTML, we connect the two, and suddenly, you can build a website entirely in your browser using natural language.</p>\n\n\n\n<p><strong>[Rich Tabor 00:08:20]</strong></p>\n\n\n\n<p>Man, that&#8217;s, that&#8217;s really interesting. It really does unlock the next, potentially the next like, wave of innovation in the WordPress experience, especially removing all the complications of getting set up and actually seeing what&#8217;s there. I think that it really could, be huge for users every day.</p>\n\n\n\n<p><strong>[Adam Zielinski 00:08:38]</strong></p>\n\n\n\n<p>Oh, here&#8217;s one more. So, edge computing is big lately, and it&#8217;s going to be bigger in the future. WordPress Playground runs on this new technology called Web Assembly, and it just happened so that a bunch of edge computing providers allows you to run web assembly on their gear. So imagine having WordPress running entirely in edge infrastructure with no centralized server.</p>\n\n\n\n<p>Truly decentralized WordPress. It could be big for a well cost of operating, but also for speed, but also even further down in the future. Imagine downloading the actual, you know, even WordPress around time to your device and having the entire website on your phone. So then you know, you&#8217;re on a train, you enter a tunnel, but you can still browse that WooCommerce store and add things to your cart even though there is no range at all.</p>\n\n\n\n<p><strong>[Rich Tabor 00:09:32]</strong></p>\n\n\n\n<p>Wow, that&#8217;s, that&#8217;s pretty crazy. How far out there do you think something like that is?</p>\n\n\n\n<p><strong>[Adam Zielinski 00:09:37]</strong></p>\n\n\n\n<p>It&#8217;s hard to tell. I mean, technically, it is possible. There are a lot of challenges with regard to privacy, right? And data security for the edge computing case specifically. As for the development tools, there was a Cloud Fest hackathon earlier this year where I was with Daniel Bachhuber, also from Automattic, and we led this exciting project that brought the WordPress development environment into the browser using a couple of editors that are out there, and this is too much of an MVP for actual production use yet, but we got it working, and we build an actual plugin on a phone without internet access.</p>\n\n\n\n<p><strong>[Rich Tabor 00:10:19]</strong></p>\n\n\n\n<p>Wow. And that was just a hackathon, just hacking at it to see what you can get.</p>\n\n\n\n<p><strong>[Adam Zielinski 00:10:23]</strong></p>\n\n\n\n<p>Yeah, it was two and a half days.</p>\n\n\n\n<p><strong>[Rich Tabor 00:10:25]</strong></p>\n\n\n\n<p>Oh, that&#8217;s awesome. That&#8217;s really cool, man. Well, this has been quite a pleasure. Thanks, Adam, for chatting all about WordPress Playground. Folks, just be sure to check out developer.WordPress.org/playground to explore, experiment, and play with WordPress Playground.</p>\n\n\n\n<p>This has been awesome, Adam.</p>\n\n\n\n<p><strong>[Adam Zielinski 00:10:43]</strong></p>\n\n\n\n<p>Thank you so much for having me, Rich.</p>\n\n\n\n<p><strong>[Josepha Haden Chomphosy 00:10:45]</strong></p>\n\n\n\n<p>What a remarkable new way of working with and experiencing WordPress. I would love to be able to find ways across the project and ecosystem to help folks see what they&#8217;re getting into before they get into it, but also, who knows what the future holds for that project. Keep an eye on it.</p>\n\n\n\n<p>(Musical interlude)</p>\n\n\n\n<p><strong>[Josepha Haden Chomphosy 00:11:10]</strong></p>\n\n\n\n<p>That brings us to our small list of big things happening right now in the WordPress project. The first one is that the Kim Parel Memorial Scholarship for WordCamp US 2023 is open, and applications for it are the WordPress Foundation will once again be offering that scholarship for Travel to WordCamp US.</p>\n\n\n\n<p>It is for specifically for women in technology, women in the WordPress space. I&#8217;ll include a link to that in the show notes.</p>\n\n\n\n<p>The second thing is WordPress&#8217; 20th anniversary is still coming, as we heard in the last podcast.</p>\n\n\n\n<p>So we have reached over 100 events that are scheduled on or around May 27th, which is WordPressâ launch date. There is still time to find your closest location and attend one of those events. And probably, there&#8217;s also time to pull together an event of your own. Head on over to wp20.WordPress.net if you would like to see events in your area.</p>\n\n\n\n<p>And the third thing is WordCamp US 2023. I realize WordCamp Europe comes before that, but the programming team actually has a really interesting thing that they&#8217;re doing this year. They have some changes to the way that they are organizing the event and finding speakers for the event. But as always, they are working very hard to make sure it is an attendee-focused event.</p>\n\n\n\n<p>I&#8217;m gonna include a link or two to some announcements that are really worthwhile there. Head on over to the podcast page to see those. And that, my friends, is your small list of big things. Thank you for tuning in today for the WordPress Briefing. I&#8217;m your host, Josepha Haden Chomphosy. Thanks again to my guests, and I&#8217;ll see y&#8217;all in a couple of weeks.&nbsp;</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 22 May 2023 12:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:17:\"Nicholas Garofalo\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:98:\"Gutenberg Times: Gutenberg Changelog #83 â WordPress 6.2.1, Gutenberg 15.7, 15.8 and experiments\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"https://gutenbergtimes.com/?post_type=podcast&p=24228\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:90:\"https://gutenbergtimes.com/podcast/gutenberg-changelog-83-wordpress-gutenberg-experiments/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:64666:\"<p>Fabian KĂ€gy and Birgit Pauli-Haack discuss the new enhancements in Gutenberg plugin releases 15.7 and 15.8 as well as the Experiments available in the plugin.</p>\n\n\n\n<p><a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-83-wordpress-gutenberg-experiments#shownotes\">Show Notes</a> / <a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-83-wordpress-gutenberg-experiments/#transcript\">Transcript</a></p>\n\n\n\n<ul>\n<li>Music:&nbsp;<a href=\"https://soundcloud.com/xirclebox\">Homer Gaines</a></li>\n\n\n\n<li>Editor:&nbsp;<a href=\"https://www.linkedin.com/in/sandy-reed/\">Sandy Reed</a></li>\n\n\n\n<li>Logo:&nbsp;<a href=\"https://markuraine.com/\">Mark Uraine</a></li>\n\n\n\n<li>Production:&nbsp;<a href=\"https://icodeforapurpose.com\">Birgit Pauli-Haack</a></li>\n</ul>\n\n\n\n<p class=\"has-larger-font-size\"></p>\n\n\n\n<h2 class=\"wp-block-heading\">Special Guest: Fabian KĂ€gy </h2>\n\n\n\n<ul>\n<li>Twitter: <a href=\"https://twitter.com/fabiankaegy\">@fabianjaegy</a></li>\n\n\n\n<li>WordPress Profile: <a href=\"https://profiles.wordpress.org/fabiankaegy/\">@fabiankaegy</a></li>\n\n\n\n<li>Personal website: <a href=\"https://fabian-kaegy.com/\">fabian-kaegy.com</a></li>\n\n\n\n<li><a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-59-extensibility-of-the-block-editor/\">Gutenberg Changelog #59 â Gutenberg 12.4, Developer Hours, Extensibility of the Block Editor and more</a></li>\n\n\n\n<li><a href=\"https://gutenberg.10up.com/\">10up Gutenberg Best Practices!</a></li>\n\n\n\n<li><a href=\"https://www.npmjs.com/package/@10up/block-components\">10up Block Components</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Announcements</h2>\n\n\n\n<ul>\n<li><a href=\"https://developer.wordpress.org/news/2023/05/whats-new-for-developers-may-2023/\">Whatâs new for developers? (May 2023)</a></li>\n\n\n\n<li><a href=\"https://developer.wordpress.org/news/2023/04/how-webpack-and-wordpress-packages-interact/\">How webpack and WordPress packages interact</a></li>\n\n\n\n<li><a href=\"https://developer.wordpress.org/news/2023/04/per-block-css-with-theme-json/\">Per-block CSS with theme.json</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/test/2023/05/04/fse-program-build-a-block-theme-summary/\">FSE Program Build a Block Theme Summary</a><a href=\"https://make.wordpress.org/test/2023/05/11/fse-program-front-page-fun-summary/\">FSE Program Front Page Fun Summary</a></li>\n\n\n\n<li><a href=\"https://wptavern.com/wordpress-themes-team-releases-stacks-a-community-theme-for-building-slide-decks\">WordPress Themes Team Releases Stacks: A Community Theme for Building Slide Decks</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">What&#8217;s released</h2>\n\n\n\n<h3 class=\"wp-block-heading\">WordPress 6.2.1 + 6.2.2</h3>\n\n\n\n<ul>\n<li><a href=\"https://wordpress.org/news/2023/05/wordpress-6-2-1-maintenance-security-release/\">WordPress 6.2.1 Maintenance &amp; Security Release</a></li>\n\n\n\n<li><a href=\"https://wordpress.org/news/2023/05/wordpress-6-2-2-security-release/\">WordPress 6.2.2 Security Release</a></li>\n\n\n\n<li><a href=\"https://wptavern.com/wordpress-6-2-2-restores-shortcode-support-in-block-templates-fixes-security-issue\">WordPress 6.2.2 Restores Shortcode Support in Block Templates, Fixes Security Issue</a></li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\">Gutenberg 15.7</h3>\n\n\n\n<ul>\n<li><a href=\"https://make.wordpress.org/core/2023/05/04/whats-new-in-gutenberg-15-7-03-may/\">Whatâs new in Gutenberg 15.7? (03 May)</a></li>\n\n\n\n<li><a href=\"https://wptavern.com/gutenberg-15-7-adds-site-logo-upload-to-inspector-controls\">Gutenberg 15.7 Adds Site Logo Upload to Inspector Controls</a></li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\">Gutenberg 15.8</h3>\n\n\n\n<p><a href=\"https://make.wordpress.org/core/2023/05/20/whats-new-in-gutenberg-15-8-may-17/\">Whatâs new in Gutenberg 15.8? (May 17)</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Experiments in Gutenberg</h2>\n\n\n\n<table><tbody><tr><th>Zoomed out view</th><td>&nbsp;Test a new zoomed out view on the site editor (Warning: The new feature is not ready. You may experience UX issues that are being addressed) (<a href=\"https://github.com/WordPress/gutenberg/pull/41156\">#41156</a>)</td></tr><tr><th>Color randomizer</th><td>&nbsp;Test the Global Styles color randomizer; a utility that lets you mix the current color palette pseudo-randomly. (<a href=\"https://github.com/WordPress/gutenberg/pull/40988\">#40988</a>)</td></tr><tr><th>Command center</th><td>Test the command center; Open it using cmd + k in the site or post editors. (<a href=\"https://github.com/WordPress/gutenberg/pull/50128\">#50128</a>)</td></tr><tr><th>Grid variation for Group block</th><td>&nbsp;Test the Grid layout type as a new variation of Group block. (<a href=\"https://github.com/WordPress/gutenberg/pull/49018\">#49018</a>)</td></tr><tr><th>Details block</th><td>&nbsp;Test the Details block (<a href=\"https://github.com/WordPress/gutenberg/pull/49808\">#49808</a>)</td></tr><tr><th>Block Theme Previews</th><td>&nbsp;Enable Block Theme Previews (<a href=\"https://github.com/WordPress/gutenberg/pull/50030\">#50030</a>)</td></tr><tr><th>Navigation block</th><td>&nbsp;Test the Navigation block using the Interactivity API (<a href=\"https://github.com/WordPress/gutenberg/pull/50041\">#50041</a>)</td></tr></tbody></table>\n\n\n\n<p class=\"has-large-font-size\">Stay in Touch</p>\n\n\n\n<div class=\"wp-block-group is-layout-flow wp-block-group-is-layout-flow\"><div class=\"wp-block-group__inner-container\">\n<ul>\n<li>Did you like this episode? <a href=\"https://lovethepodcast.com/gutenbergchangelog\"><strong>Please write us a review </strong></a></li>\n\n\n\n<li>Ping us on Twitter or send DMs with questions. <a href=\"https://twitter.com/gutenbergtimes\">@gutenbergtimes </a>and <a href=\"https://twitter.com/bph\">@bph</a>.</li>\n\n\n\n<li><em>If you have questions or suggestions, or news you want us to include, send them to <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a>. </em></li>\n\n\n\n<li><em>Please write us a review on iTunes! <a href=\"https://gutenbergtimes.com/itunes/\">(Click here to learn how)</a></em></li>\n</ul>\n</div></div>\n\n\n\n<p class=\"has-large-font-size\" id=\"transcript\">Transcript </p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: Hello and welcome to our 83rd episode of the Gutenberg Changelog Podcast. In today&#8217;s episode, we will talk about WordPress Point Release, 6.2.1, Gutenberg 15.8, and of course the previous one, Gutenberg 15.7 as well, and some of the experiments featured hiding in the Gutenberg plugin. I&#8217;m your host, Birgit Pauli-Haack, curator of the Gutenberg Times and WordPress developer advocate, and a full-time core contributor for the WordPress Open Source project.&nbsp;</p>\n\n\n\n<p>I&#8217;m so happy to have, again, Fabian KĂ€gy back on the show. It&#8217;s been a while since we talked and so much happened. We just found out, it was the episode 59 and it was in February 2022, well, it&#8217;s a whole world happened in between. So for our new listeners, Fabian KĂ€gy is the Associate Director of Editorial Engineering at 10up and a core contributor to the Gutenberg project since 2017, I think. So welcome back on the show, Fabian. How are you today?</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: Thank you so much for having me. I&#8217;m excited to be back on this.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: I&#8217;m glad you&#8217;re here. So I have to ask, editorial engineering, what does that entail at the agency 10up?</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: So that is a special, in quotation marks, &#8220;made up role&#8221;, where I started down the path of a front end engineer and over time became more and more passionate about all things editorial experience. So that is now a special role where I get to focus part of my time on actually coming up with best practices and solutions for working with a block editor and helping the entire team level up and carved out my niche.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: That&#8217;s awesome, especially because in view of the next phase of Gutenberg where it is actually all about collaboration on an editorial team, so making that a smooth experience is definitely something we all will be working on for when 6.3 come out, I think. Your input will be invaluable for your clients, as well as for the team, I think.</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: Yes. I&#8217;m very, very excited about all the things that are lined up for all of us to work on and to explore, and it&#8217;ll be fun.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: So with the developer blog, I&#8217;m part of the editorial team that does reviews and works with writers. Once in a while, we start out with Google Docs and have everybody comment on it. Some writers say, &#8220;Well, I&#8217;m waiting for that moment where I don&#8217;t have to use Google Docs anymore to collaborate with people on a post and not have to copy/paste it over.&#8221; So we are very much looking forward to that collaboration and we will be eating the Gutenberg dog food, so to speak, on the developer blog.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>Announcements</strong></h3>\n\n\n\n<p>Speaking of the developer blog, Justin Tadlock just published the What&#8217;s New for Developers in May 2023 on the developer blog, and that&#8217;s a series of roundup posts that were started in February, where we look at all the publications that come out throughout the month, what&#8217;s new in core, the Gutenberg plugin, the keeping up with Gutenberg index page, and so much more, and just pick those things that are relevant for developers not to teach them how to use them, but more like, &#8220;Watch out, this is coming,&#8221; and prepare them for an X release pretty much.&nbsp;</p>\n\n\n\n<p>The main one has quite a few items in there that are highlighted there. One is the Block Selectors API, which has definitely the markup of a larger tutorial, but it got quite a few developers excited about CSS and their blocks and being more in control of it. Another one as we will also talk about it is the first community theme and all things. So it&#8217;s pretty much a roundup of a lot of things that are interesting for extenders like plugins, developers, theme developers, and also agency developers.</p>\n\n\n\n<p>So we share the latest blog post link in the show notes, but if you haven&#8217;t looked at those yet, and if you&#8217;re a developer, subscribe to the feed of the developer blog or just for the roundup post so you get a heads up on many things.</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: I would highly encourage everybody to take a look at those because they&#8217;re super valuable, just quick shares of what&#8217;s going on, what are the things to look out for, and even if you&#8217;re not developing for the actual experimental Gutenberg plugin, it is something. It makes it so much easier when the next big WordPress update comes around to know what&#8217;s in the pipeline, what are the things that are being talked about and already have some grasp of just what&#8217;s coming.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: Well, thank you so much. Justin does a great job in putting it all together and also shares some resources that are available on Learn WordPress. Then there were two new posts since we had the last show. There was one on how Webpack and WordPress packages interact by Ryan Welcher. That really gets you a little bit more theory around how WordPress and Webpack work together. For those that are not like me, I trust the things &#8230; I trust in God. I trust in things that if I put an NPM, run something, that it&#8217;s all going to work out, but some people want to really dive into Webpack some more and this gives them a great introduction to that. How are you doing with Webpack? Are you manipulating Webpack for your own development?</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: So I used to do it a lot, especially in the early days of the WordPress Scripts package. There were so many things that were not yet a part of it, and I was very actively adding hacky solutions to add post CSS and all of those SaaS things to WordPress Scripts. That was my introduction to actually working with Webpack. Now, WordPress Scripts takes care of most of our needs or for some of the things, we have a similar tool at 10up that is a helper so we don&#8217;t have to deal with custom Webpack configurations.</p>\n\n\n\n<p>I read through that post from Ryan about how that interacts, and it&#8217;s a really solid deep dive. If you want to understand the areas, the inner workings of how some of these Webpack plugins interact, which you don&#8217;t need to, but if you want to, that is very, very useful.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: Then the other blog post was the per-block CSS with theme.json. The per-block CSS came out out of feedback from the community that custom CSS were not available anymore to put in custom CMS for the block themes and for sites, and it was introduced with 6.2, but it also needs some additional handle. Justin wrote a blog post about it, how best to think about per-block CSS with theme.json without getting too deep into the weeds and how that&#8217;s offered to the user. So definitely read up about it.&nbsp;</p>\n\n\n\n<p>For the FSE program, Anne published two summary posts and you make your part of coffee first because they&#8217;re both very long but also very detailed from the latest testing calls. One was Build Your Block Theme with the great block theme plugin and the other one was the testing call 21 for the FSE program for the front page fund summary. There will be a new testing call coming out of the FSE program.</p>\n\n\n\n<p>So if you are into block themes and users use them and all that, it&#8217;s definitely a good overview on what are the pain points, what are the team working on because Anne is very, very thorough in adding to all pain points or discussion points, also the PRs or the issue that is on GitHub about that particular topic. So you can chime in with your opinions, with your experiences, and with your testing, and it would really help if you chime in and be encouraged to actually be part of the testing project. That&#8217;s it.&nbsp;</p>\n\n\n\n<p>Of course, we share all the links in the show notes for this episode.&nbsp;</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>Community Contributions</strong></h3>\n\n\n\n<p>Another great announcement and community contribution is the first theme coming out of the community theme project where community members and team members are working together on creating block themes and the first one is called Stacks. It&#8217;s a theme with which you can build slide decks. It&#8217;s a very interesting approach to a website that is more a slide deck rather than have navigation from page to page to page. It&#8217;s more like a guided tool that you can use it or you can use it for your next presentation, but you don&#8217;t have to use a third-party tool for that if you want to spin up a website and just use it for your presentation.&nbsp;</p>\n\n\n\n<p>It&#8217;s quite interesting to see how that comes together. The code is certainly available on GitHub and we share both the announcement post, as well as the write up by Sarah Gooding on the WP Tavern for you.</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: These explorations and these themes and plugins that allow you to build your slide deck in the block editor, I&#8217;m always amazed when I see that. I think a couple of years ago, Ella was maybe one of the first ones who did talk at a React conference and blew my mind in the end when they revealed, &#8220;Hey, and all of this was created in the block editor and these slides are powered by it.&#8221; I think Nick Diego also did it at WordCamp US or at WordCamp and it&#8217;s always pretty cool to see.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: You&#8217;re right. Nick Diego did it at WordCamp US for his talk, Build A Block in 15 minutes, and he built actually that slide back there as well. It&#8217;s very interesting how this can be used on your own website. Yes, Ella had a slide. It was actually a block that she added. I think it was the same for Nick Diego and now we have a theme for it. So it&#8217;s really cool.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>Whatâs Released</strong></h3>\n\n\n\n<p>All right. That brings us into what&#8217;s released and, of course, let&#8217;s start with the minor release for WordPress, the 6.2.1 Point Release that just came out this week and there were a few hiccups there. Do you want to talk about this and what&#8217;s happening there?</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: Sure. So 6.2.1 was released, I believe it was at some point early this week. One thing, there was a security issue that the security team took care of and made sure that that gets resolved as quickly as possible, but that security issue essentially resulted in short codes no longer working in block templates. So in a block-based theme, if you have a short code inside a block template, that will no longer actually get converted to the dynamic data. That has caused some issues for folks, especially around auto updates because it&#8217;s just a minor patch release, but it is breaking some existing sites, which as always, it is a very difficult choice to make and a very unfortunate thing when that has to happen because of security thing.&nbsp;</p>\n\n\n\n<p>There is an open issue in track where a lot of this is getting discussed right now, and it was discussed in the core chat yesterday, where essentially, it is very unfortunate when something like that has to happen. From my perspective, I think the team, if there is a security issue, that is the only thing that can be done. The only thing that I think we as a community can try to be a little better at is communicating those types of things ahead so folks are more aware of that, &#8220;Hey, we needed to make a difficult decision here. Beware, you should make this update, but here are some things that you can do instead to help your site still be up there,&#8221; because the communication around the issue could have been a little better.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: I don&#8217;t think there&#8217;s no maybe about it, but it was a little obscure in the change log and it wasn&#8217;t saying, &#8220;Okay. It&#8217;s going to break sites,&#8221; but I think it&#8217;s really hard to also suggest a solution right now. So Jean Baptist Audras was one of the release leads together with George Mamadoshvilli, and he wrote in the core dev chat on Wednesday night, &#8220;The release itself went pretty well. Thanks everyone for your patience. However, as you may know, one security fix led to the important issues with the short codes used in templates, but it was not templates per se, but block templates in block themes. So the issue is currently actively discussed in the security editor team and some hypotheses have been made to sort this out in a quick followup release. No schedule is available right now because the discussions haven&#8217;t been finished yet, but it will depend on the followup patch currently discussed by the editor team.&#8221;</p>\n\n\n\n<p>So to just point out, and Paul Byron had actually &#8230; All the solutions on how to deal with it right now in the emergency situation when you see dozens or even hundreds of page breaks, one is to roll back to 6.2 with a core rollback plugin, use the short code, and put them in template parts. That seems to be working in the block themes that you put the short code in a template part and add that template part to the template or have &#8230; In the ticket that you mentioned, Fabian, there were also a code example on how to introduce making the shortcuts work again, but all three of them introduced the security issue again.&nbsp;</p>\n\n\n\n<p>So I&#8217;m not sure quite how to advise people to work, but there are no good choices right now because you are caught between you want your client&#8217;s side to work, but you also don&#8217;t want their security issue to be out there too long. So the core editor team is definitely working on a solution to fix the security fix, but all, what I just said, is actually just introducing back the security issue into your sites.&nbsp;</p>\n\n\n\n<p>So there are also opinions that short codes might be a legacy way of dealing with things. Maybe it&#8217;s a good call for converting the most important short codes to blocks and use them for the block editor instead of &#8230; but not everybody has the capacity for it, not everybody has the time for it or they&#8217;re just not there yet, but the plugins that they use are also not converting the shortcuts to blocks. So it&#8217;s the nature of the beast. I don&#8217;t think the shortcuts will ever go away, but there&#8217;s a better way to handle that.</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: Yeah, definitely. In regards to the various options that we have right now, rolling back and that plugin that exists and that code that you can add to your theme, those all add back the vulnerability, like you said. I wasn&#8217;t sure from my understanding whether putting the short code in the template part actually caused any issues. I thought that that was the best proposed solution even though it&#8217;s clunky to have to deal with template parts for those areas individually, but from my understanding, that was the best outcome where you&#8217;re not really introducing the security vulnerability, but also can retain your feature or the look of your site. So I think that is the best option right now, but yeah, it is a little opaque.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: Good point. Thank you for pointing that out again. Okay. The rest of 6.2.1, quite a few bug fixes for core, as well as for the editor that were found during the release of 6.2 and didn&#8217;t make it into 6.2, but that&#8217;s why the followup release was really on the schedule relatively to the 6.2 release. We will also share the changelog for the release in the show notes, as well as the tickets for the discussion. Paul Byron also added that solution with the template parts to the ticket so you have it all in one place to look up for if you want to follow up on that.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>Gutenberg 15.7</strong></h3>\n\n\n\n<p>All right. Next one up was Gutenberg 15.7 and it had quite a few enhancements. One is that as group and media texts have now allowed blocks attributes that can be passed to the inner block props, so to speak, that means that you can control which blocks can be added to a certain group or a media text block if you wanted to.</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: That is a really useful thing for extenders or theme builders or if you create a pattern that is meant to be a certain thing, you&#8217;re now able to restrict which other blocks can be used within that area, which can be super useful when you build a call to action and have some styling around that and don&#8217;t want to support a table to be in that call to action, for example. This is so useful to be able to do that. So we don&#8217;t have to build the custom block for it, but instead we can create a pattern and have all those options and can curate that editorial experience to really, the level that we want to curate it to. With the template and template block, we were able to do some things, but now with the allowed blocks, we have most of the controls of an actual inner block area also exposed for these blocks that support inner blocks, which is very useful, I think.&nbsp;</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: Excellent.&nbsp;</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: Next up, we have the site logo added a replacement flow that allows you to change out the actual logo using the inspector control. That is just an addition, an alternative way that you can deal with the site logo essentially. You can still use the inline controls, but while you are in the sidebar tweaking your spacing or any other visual controls, you can also quickly swap out the media there, which I think is an interesting approach to this.</p>\n\n\n\n<p>For this one in particular, I&#8217;m interested to see the feedback around it because for the most part, we&#8217;ve been very strict about there should be direct manipulation of content right in the editor canvas and not many controls should live in the inspector controls. It&#8217;s not removing it from the inline, but it&#8217;s also adding that secondary way of manipulating it to the inspector controls. I&#8217;m very curious to see how that will play out and how that may affect just how we use this.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: So inspector controls is just another way to say sidebar, just make sure where those tools are when you first encounter them. I think it comes more like we want to be a parity with a customizer. That&#8217;s one more step. Then in the inspector in the sidebar, when you replace the media, you are going right directly to the media library and select that. So you don&#8217;t have to &#8230; It seems to be a slightly different workflow than it is from the toolbar.&nbsp;</p>\n\n\n\n<p>So the next feature is actually a really cool addition or enhancement of the fluid typography. So when the fluid typography was introduced first in 6.1, it still had the problem that if you have very large fonts, they wouldn&#8217;t go small enough for the mobile version because the calculations would stop and it would still be too big. This feature introduces a logarithmic scale factor to calculate the minimum font size and now the font adopts to all screen sizes. Even if you have a 68 or 102 pixel font, it will scale down to a mobile version and not stop at 50 or something like that.&nbsp;</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: The next thing on the list here is the behavior of the top toolbar has been changed, and that is for a long time now you&#8217;ve been able to using that user settings menu in the upright corner change the behavior of the block toolbar to no longer be attached to the actual block, but instead always be fixed at the top of the editor. The behavior of that has been changed so that you can collapse that toolbar and still have it available there, but because the space in that top toolbar is quite sparse, that allows for just some more flexibility with how things are getting laid out there.&nbsp;</p>\n\n\n\n<p>There are a couple more things that we&#8217;ll talk about later that were changed about the overall layout of that tool toolbar. Actually, I like it very much the way that it&#8217;s coming together and with some of the explorations happening there. I really like the direction where a lot of this is going right now.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: It also fixed &#8230; One particular thing that was still missing is that you now have access to the parent block, which on the block toolbar you were always able to select the parent toolbar and then the sidebar changed and everything. When you had the toolbar fixed on the top, you wouldn&#8217;t have that particular icon available to click on to manipulate the parent block. That has changed too, and it came in with that particular feature there.&nbsp;</p>\n\n\n\n<p>I was always 50/50. Some weeks I like having the block toolbar right on the block, especially when I&#8217;m further down on the block page, and sometimes I just want it on the top and I&#8217;m changing it all the time. I don&#8217;t know how you do it. So I have not tested this new toolbar fixed setting yet, but I definitely will. I read through the comments and there are some discussions. So please add your feedback and your experiences to it and what you think about it to make it the best it can be.</p>\n\n\n\n<p>The next is that the image block now also displays &#8230; No, it&#8217;s not the image block, it&#8217;s when an image is in a block or in a template, it now also displays the borders on the placeholder. So if you have a template that gives you all the series of blocks and each block you want the feature image there, you will also see now in the placeholder the color of the borders, including the color of it. So it makes your choices of images maybe even smoother. It&#8217;s very subtle, but it&#8217;s definitely a live quality enhancement that I definitely like because sometimes you just need to have a picture that does not clash with your borders if you had a design option that image has borders.</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: It just makes your life a lot easier when you&#8217;re creating a template and you don&#8217;t &#8230; Before this when there was a placeholder where no actual image was selected for the post, it was just difficult to gauge, &#8220;Hey, how do these border controls actually affect this?&#8221; Having the placeholder resemble the actual image much closer and retain all of those border controls is just a very good thing.&nbsp;</p>\n\n\n\n<p>Next up, we have a change in experiment for the actual pattern insertion modal, which I am really excited about. When you use the pattern instruction modal, you know that all of the various patterns are displayed in a grid, and that grid can look a little weird sometimes because it&#8217;s very staggered how these &#8230; Some patterns are very tall, and then the next one is very narrow, very short. There&#8217;s a lot of white space in that modal. This option here tries a masonry layout where they actually &#8230; If you&#8217;ve ever used Pinterest, it&#8217;s essentially that type of layout where it just fills all that white space and it&#8217;s showing all of those, I think, in a more elegant fashion and it just makes that look a little more refined. I&#8217;m very happy to see that.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: It&#8217;s definitely a more natural look for the pattern modal. The next feature is that duotone block controls are now added to the sidebar. They were hidden before in the block toolbar and you had to know that they are there and the icon was a little bit obscure. Then the options when you do it in the block toolbar is it feels like you are in the wrong place to make those decisions, and now you can make them from the sidebar. I really like that. It&#8217;s a clear adoption to the interfaces that we saw from other design tools.</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: Next up, in the accessibility section, there are some refactors of how the ARIA attributes for the list view have been modified, which makes it much easier and much more accessible to navigate through the list view. It&#8217;s always good to see those enhancements over time.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: Those ARIA levels, there were quite a few in the list view, so there was a major overhaul of the display of the list view. I think Alex Stein did some great work there to make it happen and put it over the finish line.</p>\n\n\n\n<p>So I&#8217;m scrolling a little bit further down to the changelog and I have the feeling we are done with 15.7. It was a smaller release, but it had definitely some great features in there.&nbsp;</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>Gutenberg 15.8</strong></h3>\n\n\n\n<p>We are now coming up with 15.8. Fabian, you were the release lead on that. Do you want to kind of kick it off and let us know what&#8217;s in there?</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: Sure. So there were a couple of major features which get their introduction here, which is always fun. One of them is the addition of a command center. There actually is &#8230; There was a post on the make blog from Riad that I&#8217;m sure will get added to the release note or to the podcast notes here that explains a little bit more in depth what this command center actually is. Right now, it is an experiment, but it essentially like spotlights on a Mac, for example, or some of these launchers. You have a quick keyboard command. In this case, it&#8217;s command K, to launch essentially, an open prompt field where you can put in your prompts and jump to different places of the editor or create new pages or just perform quick actions.&nbsp;</p>\n\n\n\n<p>It&#8217;s also meant to be extendable and meant to be something that plugin developers can hook into and allow users to actually quickly navigate their site and perform actions. I&#8217;m really excited to see if this comes to life and explore how this ships out in the future. With this feature, I&#8217;m so here for it, I&#8217;m so excited about it. I cannot wait for the day where this gets expanded outside of the editor view and is just available in all of the screens of WordPress because right now, it is limited to the editor screens, but I think in the future, this will be available in all of the pages of the admin of WordPress. I&#8217;m so looking forward to that.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: Riad&#8217;s post on the Make Core Blog &#8230; Blog and block, sometimes I get it mixed up, but I did it right this time. It&#8217;s the Make Core Blog. It&#8217;s called Command Center and Request for Feedback. So he explains what the prototype is. There&#8217;s also a small little video that quickly shows you how it works and then explains the API and the static commands and also what dynamic commands are, definitely, and the contextual commands. So there are three commands that you can have it use, but it&#8217;s also the extendability in mind for plugin developers.&nbsp;</p>\n\n\n\n<p>I think it also triggered a few things. If you want to employ an AI to use within the block editor, having a standard interface that can call AI commands is certainly beneficial to the editor. So as Fabian said, I will share the post in the show notes so you can chime in and see what you think about it and how it works. It&#8217;s really hard to describe on a podcast, audio podcast, for that reason.</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: As somebody who has championed extensibility and plugability in the editor for such a long time, I&#8217;m so happy to see how this feature is getting rolled out and how it is built with that extendability and plugability from the very beginning. So I&#8217;m really excited about this.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: If you want to try it, it&#8217;s still behind the experiment flag. You need to go to install the plugin 15.8 and then go to the Gutenberg menu on your WP admin and then there&#8217;s an experiments page and you need to check the mark for the command center to actually be able to test it.&nbsp;</p>\n\n\n\n<p>The next item on the list is a new feature as well, and the first version of the revisions UI for the global styles, so all the talk about global styles and new features and new options to change things. Some people want to try just something out and then revert to the previous version and there was no revision available for the global styles. Now, there is, and it has actually some nice features. When you have the site editor style, the style site open and click on the revisions, it will show you a history of the revisions, and when you click on the items, it will show you a version of it on the canvas and you can also compare versions.&nbsp;</p>\n\n\n\n<p>So I think it&#8217;s getting there. It definitely needs some more refinement in terms of what information will be there, how many revisions are we showing, and all that. So that&#8217;s a really interesting progression on this global styles editing.</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: If you&#8217;ve ever used revisions of a standard post or a page since the block editor was introduced, this is a great feature for global styles and I think it&#8217;s the right thing to roll it out for this first, but the live preview of a revision in a rich preview makes me so excited for a future where we can eventually get rid of the existing code view of revisions for standard post content stuff and actually show rich previews of that because, especially since the introduction of blocks, the revisions UI is just really, really difficult for non-technical people and even technical people to really manage because you just get a code view and are trying to figure out what changed.&nbsp;</p>\n\n\n\n<p>This year is a visual preview of what revisions look like for global styles and it&#8217;s making me so excited about what&#8217;s to come for more other visuals or revisions in the future.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: I totally agree that revisions for the posts and pages are on the board for the collaboration project, the phase three of Gutenberg and making revisions be aware is definitely something we are all looking forward to.&nbsp;</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: Next up, we have the inspector panel. So again we&#8217;re talking about that right-hand sidebar of the global styles panel is now getting or got a refactor to make it work and look more similar to how it works on the standard post. I think that for a long time had been an area of confusion for me where if you wanted to change the typography options or color options in the global styles, the interface was just structured completely differently to how it is structured when you just select a paragraph block, for example, in the standard editor. This is unifying those two experiences to be alike and that just lifts a whole bunch of cognitive load that you have to think about and just makes it work the same way in both of those areas.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: Excellent. In the same way, there is now a details block. We talked about it on the show before. That is in experiments and it now has been enhanced to be able to use InnerBlocks in the details of the spoiler alert block. I call it spoiler alert because the detailed summary that&#8217;s as broad idea that some people don&#8217;t know what we&#8217;re talking about, but you have a sentence or just a headline, and then you get an arrow and then it reveals additional content. You can use it to talk about spoilers in your book review or in your film review or you can hide details that only a certain amount of readers will need about a technical thing or so. In the earlier versions, you only could add a paragraph to those details or only paragraph blocks and now you can add images, you can add quotes and all that. So this is definitely an enrichment of the details block. Also an experiment though.</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: That is really something &#8230; I know I have been involved with those conversations of the details block for way too long already, but I&#8217;m really looking forward to getting the community feedback of just what&#8217;s available there. It&#8217;s a very difficult thing because the detailed summary is essentially an accordion, but there are some accessibility issues that make it not the best use case for an accordion. So with these changes, just I&#8217;m interested in the feedback of the community of how they&#8217;re able to use all of the design tools to make it function the way they want to or whether there are struggles because this changes a little bit of what was there before and there were some more design options that you had with that earlier approach, but it also was a little less intuitive because it had more levels of nesting and the summary element was its own block and was just more complicated, and this is a much simpler implementation of that block. Also, it therefore removes some of the options that you have available. I&#8217;m really interested to see how that plays out and what people will think about it.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: Many, many, almost all block collections that came out when the block editor first was released had an accordion block in there. A lot of people liked it for FAQs and for how-tos and all that, but it was interesting, I really didn&#8217;t really know why there wasn&#8217;t an accordion block in core until I read through the discussions about the details and summary. Some people will make it work as an accordion, but what the accordion does, it knows about the other block. So you have an accordion. The first is the tab on top and then you have details and then you have another tab and then the details and each accordion knows about the other one being open or not open. That&#8217;s very hard to replicate in a model way how the block editor works.&nbsp;</p>\n\n\n\n<p>I tested the details in summary block that&#8217;s in the experiment right now with 15.8 and I didn&#8217;t find it particularly easy to navigate because it had some hiccups. I don&#8217;t know how to get out of it. Normally, if you have a list block, when you hit enter twice, you&#8217;re out of it and then you can add additional blocks to it. There are no visual cues when you are in the block writing or adding additional blocks. There are no visual cues, are you still in the details section or are you not? The summary, there is no way to get from the summary to the details block per keyboard. You need to change controls on it.&nbsp;</p>\n\n\n\n<p>So there are a few things, but that&#8217;s why it&#8217;s behind the experimental flag and not yet completely released. So do as a favor and enable that test, that experiment so you can also test it. As Fabian said, community input is wanted and necessary.&nbsp;</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: Next up, there is another addition to the site editor and that is in the main sidebar of the site editor. There now is a new menu item called Pages that allows you to view the 10 most latest edited pages of your site and directly jump in and edit them. That is one step of actually making content editing in the site editor more possible. Again, that was one of the features that was there in earlier revisions of the site editor but then got taken out before it got released in I believe it was 6.1. These are explorations of slowly adding that content editability back into the site editor. It&#8217;s really interesting to see how that works. It is so difficult how to best communicate with the user when you&#8217;re editing parts of a template versus when you&#8217;re editing parts of the actual content of a page.&nbsp;</p>\n\n\n\n<p>I think that that will still be the most difficult issue to solve for here, but this is slowly introducing that back into the site editor and it is really cool to see just having all of those things in there.&nbsp;</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: Look at the menu item on the left-hand side, as other people say the dark side of the site editor, but it&#8217;s there. So the next item or feature that got introduced makes Fabian really, really happy and it&#8217;s the introduction of the plugin template settings panel slot, which means on the sidebar, there is now a way for plugin developers to extend the feature set that&#8217;s displayed to the user. Have you tried it out yet? Have you looked at that feature?</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: I&#8217;ve not yet had a chance to play with it, but yeah, more slots and more places for extenders to add to the experience and showcase custom settings and those types of things always make me happy, especially when they&#8217;re done right, and this seems pretty cool.&nbsp;</p>\n\n\n\n<p>Next up, we have an update that is very useful for extenders again. It consolidates and adds some more documentations to the storybook. If you&#8217;re not familiar with the storybook, that is actually something when you go to the GitHub repository of the Gutenberg plugin, in the right-hand sidebar there is, I think it&#8217;s called pages or deployments. You can actually jump to that storybook right from GitHub and view it. The storybook essentially is showcasing all of the various React components that were built as part of the Gutenberg plugin and are available in WordPress core and is showing live previews of them with some controls. You can tweak some of the settings right there visually and also have some of the documentation there. This consolidates and changes a little bit of just how that is structured and how that appears. Just in general, the storybook that has been there for a long time is a super valuable and great tool and it&#8217;s always nice to see additional enhancements for that.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: I definitely want to point that out that at WordCamp Asia, I heard from a few people that were at the contributor day and working with the core editor table there, they were really surprised that many developers that came and wanted to work on things did not know about the storybook. I think we have not done a good job in explaining what it is and pointing people to it. I think it&#8217;s part of the documentation that is in the components, but it&#8217;s not referred to &#8230; Most of the time, it&#8217;s not referred to in the documentation on the developer site in the block editor handbook. We are going to change that a little bit and add more links to the storybook for the various components because it&#8217;s such a rich developer experience where you can change things and then you click on a button and it gives you the code for it for the changes that you made and you can immediately reuse it in your own code base. Definitely, I take any chance when I can talk about the storybook now.</p>\n\n\n\n<p>The next part is a feature for the block editor that is talking about the dimension controls and it&#8217;s not always visible. So now, it&#8217;s an attempt to show all the dimensions control at the beginning and not hide them so much where you had to open them and then decide do you want to see the padding, do you want to see the margin. It&#8217;s now easily available so you don&#8217;t have to look for it, what padding and margins is, because we all talk about padding and margins, but we never talk about dimension controls. So when the words appear on the screen, you don&#8217;t as easily recognize that that&#8217;s what you&#8217;re talking about.</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: This, again, is also something where it is just difficult and interesting. The vertical space that we have available in the sidebar is very limited and it&#8217;s always an interesting balance to strike of how much do we show by default versus how much do we hide behind the setting so it&#8217;s not overwhelming for somebody that is new to the editor, but also makes it discoverable for somebody. So it is not changing any of the features that are available, but it is trying to show some more by default. I&#8217;m very interested to see how folks will react to that, whether it feels overwhelming or whether it makes it more approachable. The only real way to find that out is by actually testing that. So I&#8217;m glad to see those explorations happening in the plugin.&nbsp;</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: It might go away again or will be tweaked later on. So your comments are certainly wanted and necessary. We share in the show notes the release post for 15.7, the release post for 15.8. By the time you listen to this, Fabian will have published it, and I&#8217;m sure also, Sarah Gooding will talk about both releases or already has on 15.7 and 15.8.&nbsp;</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>Whatâs in Active Development or Discussed</strong></h3>\n\n\n\n<p>or I just wanted to at the end of it &#8230; So those were all the releases and we are now talking about what&#8217;s in active development or discussed. We have right now the largest number of experiments in the block editor since the beginning. I think there are now seven experiments hiding on the experiments page for the plugin. So let&#8217;s talk about them. Some of them we already talked about. So it starts out with a zoomed out view and it&#8217;s test a new zoomed out view on the site editor. So I&#8217;m reading from the page now and it also has a warning attached to it, &#8220;The new feature is not ready. You may experience UX issues that are being addressed.&#8221; UX means user experience, just to clarify that. Did you test that before?</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: Yeah. So the zoomed out view essentially means that you can more quickly navigate through or get a more holistic view of your page and not appearing in the same size as you would always see it, but instead, it zooms out and shows you more of your entire page smaller in the canvas. That is very useful when you want to make changes to your global styles and just want to see how it affects your site more holistically or when you tweak those things. Especially when you switch between block theme variations, that is just useful to see how it will not just affect that very small area of the site that you see in your viewport, but instead see it more broadly for an entire page.&nbsp;</p>\n\n\n\n<p>So I think this is a great thing to work on. Right now, as the warning says, there are some issues that are being worked on. Especially for working with global styles, having that more zoomed out view is very useful.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: So if you tested it and you have an idea how to make it better, definitely air those on GitHub and filing an issue of that. So the second one, it says color randomizer, test the global styles color randomizer, a utility that lets you mix the current color palette pseudo- randomly. I think it&#8217;s one of those features where it said, &#8220;Okay. It&#8217;s cool to have and cool to test things out, but it&#8217;s not something that a lot of people would think they needed.&#8221; Do you have any thoughts on it?&nbsp;</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: It is one of those features where from my perspective as somebody who works a lot in the large agency space, that is not a feature I would&#8217;ve ever come up with, but I can see how, especially if you&#8217;re somebody who&#8217;s just playing around in the editor trying to build a new design, it can be a useful partner to give you some inspiration of maybe you&#8217;re not the best with color theory and coming up with an accessible color palette yourself, and that can be a great way to get some inspiration for just showing you different variations of what your site could look like with different colors and spark some of that imagination, but it is one of those features that I know for a client site that has a design guide with strict color I would want to disable that feature and would not want to expose certain clients to that feature. So it&#8217;s definitely one of those where I can see it being useful for some, but also rather distracting for others. So I&#8217;m interested to see how that will actually get rolled out.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: It might also be part of the explorations, but the design team does in figuring out is there a way to include different palettes that are on third-party sites that can come in and you can choose from, but I think it&#8217;s not a high priority right now for the team. That&#8217;s why it&#8217;s all still in the experimental phase and it hasn&#8217;t gone that route yet. I heard Matt Mullenweg and one of his state of the word talking about making color palettes that are out in the universe interesting, available to site builders or site owners in some way or shape.&nbsp;</p>\n\n\n\n<p>The third test item on the page is the command center, a test of command center, open it up using command K in the site of post editor. We talked about it. I don&#8217;t think we need to elaborate some more, but that&#8217;s where you find it.&nbsp;</p>\n\n\n\n<p>The fourth one is the grid variation for a group block, test the grid layout type as a new variation for the group block. Right now, that only works on the site editor because it&#8217;s actually a template or site design approach to the grid. Grid, it&#8217;s actually a CSS feature. So this tries to explore how you can make templates that adhere to a certain grid layout, but I&#8217;m not as knowledgeable about design to be able to use that. I think I need a little pre-beginner&#8217;s tutorial for that.&nbsp;</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: It is. I am really happy to see this exploration being done right now. In the last couple of years, we got that row and stack variation of the group block, which essentially as a developer, that is my flex box. Flex box allows you to layout content in one direction, so either horizontally, the row, or vertically with the stack. The grid, you can achieve some of those grid layouts with the columns block, but the columns block, it is very difficult for it to wrap around. So if you wanted to, let&#8217;s say, have a three column grid that is not just one free column layout, but instead has two rows of those two columns, that is not really or is technically possible, but it is not ideal. That is where grid layouts come into play and are, I think, so much more powerful.</p>\n\n\n\n<p>I think there also is an exploration that is not listed here of adding an actual grid layout or using CSS grid layout for the grid in the query block. We weren&#8217;t able to use grid when the editor first came out because it was too new of a CSS feature and we needed to support more older browsers, but that browser support has changed so much in the last couple of years that we&#8217;re now able to use grid in the editor. It just opens up so many new design possibilities and makes it so much easier.&nbsp;</p>\n\n\n\n<p>I&#8217;ll say on the custom development side, grid block is one of the first things that we build on one or a grid block is one of the first things we build on many custom sites because it is just much more powerful than the columns block and also easier to use in a way. So I&#8217;m excited for these explorations.&nbsp;</p>\n\n\n\n<p>I will say though, a couple of releases ago, the group block changed to show that variation picker when you first insert it where you have to pick between the variations. I&#8217;m not yet sure I&#8217;m in love with that approach of &#8230; I like the various variations of the group block, but when I add a new group, it always pauses me a little too much because I need to step back and, &#8220;Hey, I just want to start with a default grid or a default group and then continue with it.&#8221; So I&#8217;m happy for more of these variations of the group block and for more of those layout controls. I&#8217;m not quite sure we have found the best way to expose them.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: I hear you. Making the decision to use a group block now becomes also a decision of what kind of flow you want and you are not there yet. When you get the group block, I understand that, but I&#8217;m also excited for the grid layout in terms of it is a feature that was requested quite a bit in the early days of the block editor layout site editing things, and it&#8217;s still missing. So now, certain plug-ins and block collections and theme collections have stepped in and allowed that already. So core is a little bit behind on that, but of course, core has a different outlook for the site editor than plugin developers have.&nbsp;</p>\n\n\n\n<p>The fifth experiment in the experiments page is the details block with the detailed summary block. We talked about it. It&#8217;s there for you to test out.</p>\n\n\n\n<p>The sixth one is the block theme previews, and it enables block theme previews. That&#8217;s not much of an explanation, but what it allows you is on your site &#8230; So the customizer had the live preview of themes that were already installed on your site so you can see how your site would need to change to when a theme would be activated. It&#8217;s more a decision making tool rather than a good design tool.&nbsp;</p>\n\n\n\n<p>So with many, many block themes coming online, we are now beyond 300 in the directory. I think the largest number is 306. I think it helps with the decision if you want to change your theme out to have a better preview, and the customers that preview doesn&#8217;t work with it. This is the first iteration. I ran that through themes through the preview and it was a great experience, so much better than the original one to review certain parts of an existing site.</p>\n\n\n\n<p>It also revealed that not all block themes are alike. There are significant differences, and having a tool to actually explore those differences or even notice them is invaluable, definitely. Not every theme behaves with this live preview feature in it, so if you are working on themes and either you have a starting theme in an agency or you use a collection of themes to build your sites to choose from, you might want to test them with this theme preview so you can turn on and off features and showcase a few things that are available in the preview.&nbsp;</p>\n\n\n\n<p>Also, please, please comment on the issues or file issues on GitHub after your tests. I already found one that when I look for style variation and I want to see how a page changed the style variation, I don&#8217;t have a way to do this because the page that is linked, the link doesn&#8217;t go to the preview, it goes to the page in the template editor, and all of a sudden, I&#8217;m out of my mindset on a preview, but all of a sudden it gets me into the editor. So that&#8217;s common for things that are in testing, but it also needs to be pointed out that that&#8217;s a major stumbling point for someone who uses the feature for the first time.&nbsp;</p>\n\n\n\n<p>The last one of the tests has just come in. It&#8217;s a navigation block that uses the still in Experiment interactivity API, and I have not used it. Did you look at that, Fabian?</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: I looked at it briefly, but the summary of it is if you&#8217;re using it and you notice a difference that worked before, there&#8217;s a bug because this essentially swaps out the engine, but you should notice it as an end user. It changes how the front end JavaScript of the site works to use that interactivity API, but instead of some custom JavaScript that was purposefully written for this, using that interactivity API to make it more declarative, but as an end user, toggling that setting should not change anything about it works. Yeah, it may produce the actual bundle size, therefore make your site a little bit faster, but usability wise, there should be no difference and there should be full-on feature parity with how the navigation works today before or after you switch that setting.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: Good to know. So if you don&#8217;t notice anything, it&#8217;s okay. Excellent. So this brings us to the end of the show today. Well, I think we talked a lot about all the new things that come to block editor and to WordPress. Thank you so much for joining me today. Fabian, is there anything that you want our listeners to know about the block editor, about WordPress, about 10up? Now is the chance to talk about it and we&#8217;ll add links to the show notes. I just wanted to say about 10up, you have a wonderful educational site about the block editor with quite a few white papers and tutorials. How did that come about? Is it your work orâŠ?</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: Yeah. The <a href=\"https://gutenberg.10up.com/\">gutenberg.10up.com</a> website, our block editor best practice site has been my baby for the last year and a half or so, where I got to spend a lot of time actually writing down how we as an agency approach working with the block editor and setting up the best practices for how to do that in the agency setting for that special type of client. Whereas the main documentation of core is more geared to end users, which is the right thing, but because of that, we decided that there is space for an additional resource to focus on the things that are important for those very curated experience for big clients and so forth.&nbsp;</p>\n\n\n\n<p>So that is one thing that I would mention, just taking a look at that <a href=\"https://gutenberg.10up.com/\">gutenberg.10up.com</a> website, and if you have any feedback on that, feel free to reach out anywhere on the Make Slack or on Twitter or MasĂ©von or Blue Sky or wherever you can find me pretty much always talking about block editor stuff.&nbsp;</p>\n\n\n\n<p>Then the other thing that I will just mention is the 10up block components NPM package, which is my passion project and has been for the last three years or so, which essentially is a collection of React components that work like all of the WordPress packages, the WordPress components, WordPress block editor components. It is a collection of additional components that are adding sometimes very complex, sometimes easy functionality for you to build. If you build custom blocks, making that a whole lot easier so you have to write less code and know that it&#8217;s tested and is working with the way that it should, and doing that in a way that feels 100% like it is just core WordPress. I&#8217;m very happy and proud of that project. If you find it useful or if you have questions or feedback about that, always happy to chat.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: Well, thank you so much. There&#8217;s some great resources. You mentioned custom blocks. There has been discussion around static block with this dynamic blocks. Where do you land?</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: The way I think about it, if I&#8217;m building a plugin that is meant for the official directory where I as a developer do not have access to the site where the code is running on, I would go with a static block unless I need to show dynamic data. If I as the developer can access and have maintenance over the site I built dynamic blocks, and that means in the agency context where we&#8217;re often changing designs, making quick iterations, we are, for the most part, only building dynamic blocks because of that because we cannot spend the time to deal with deprecations and all of those things.&nbsp;</p>\n\n\n\n<p>It really comes down to that where if you have &#8230; The thing that you should ask yourself is, &#8220;What should happen when I need to change something about this block on a code level? Should all of the old instances that maybe were published three years ago, should they also get those updates automatically or should I not &#8230; Should that historical content stay untouched and just stay the way that it was?&#8221; If it should stay in touch, static blocks is your right answer. That is the way to go. If it should update in all instances or if you need to modify the block structure very often and have access to the maintenance there, dynamic blocks are much easier to deal with and are &#8230; So I&#8217;m coming down most of the time on the dynamic side.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: Dynamic blocks side. All right. So well, thank you for answering these quick questions and having some insight in how you work as a longtime block editor adopter and in the agencies. It was a great pleasure talking to you, Fabian. We will share all the links that you mentioned, of course, in the show notes. Before we end the show, oh, what&#8217;s your Twitter handle, Fabian?</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: My full name spelled out, so F-A-B-I-A-N-K-A-E-G-Y, just all spelled together. You should be able to search for it and it should come up.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: That&#8217;s just for the people who don&#8217;t go through the show notes. We, of course, have all the links in the show notes. As always, the show notes will be published on gutenbergtimes.com/podcast. This is episode 83. If you have questions, suggestions, and news that you want us to include in the next show, please send them to <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a>. That&#8217;s c<a href=\"mailto:hangelog@gutenbergtimes.com\">hangelog@gutenbergtimes.com</a>. Thank you all for listening. Thank you for being here, Fabian. This is goodbye and I wish you a wonderful weekend.</p>\n\n\n\n<p><em>Fabian KĂ€gy</em>: Thank you so much for having me.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 21 May 2023 08:18:47 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:19:\"Gutenberg Changelog\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:93:\"WPTavern: WordPress 6.2.2 Restores Shortcode Support in Block Templates, Fixes Security Issue\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:30:\"https://wptavern.com/?p=145264\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:103:\"https://wptavern.com/wordpress-6-2-2-restores-shortcode-support-in-block-templates-fixes-security-issue\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1593:\"<p><a href=\"https://wordpress.org/news/2023/05/wordpress-6-2-2-security-release/\">WordPress 6.2.2</a> was released early this morning as a rapid follow-up to 6.2.1, which introduced a bug that <a href=\"https://wptavern.com/wordpress-6-2-1-update-breaks-shortcode-support-in-block-templates\">broke shortcode support in block templates</a>. Version 6.2.1 was also an important security release, but due to the catastrophic breakage for those using shortcodes in block templates, some users were implementing insecure workarounds or simply downgrading to 6.2 to keep critical functionality working on their websites.</p>\n\n\n\n<p>WordPress contributors worked quickly over the weekend to ensure that users can now update to 6.2.2 with their shortcodes intact. The release post identified the removal of shorcode support in the previous release as &#8220;a regression&#8221; and a bug. This is an important recognition, as shortcodes are still a tool that users frequently rely on to insert functionality from plugins that haven&#8217;t made it available as a block, as well as a necessity for things that won&#8217;t work without inline shortcodes.  </p>\n\n\n\n<p>Version 6.2.2 is also a security release, as core contributor Jonathan Desrosiers said that the issue patched in 6.2.1 &#8220;needed further hardening&#8221; in this update.</p>\n\n\n\n<p>Users are advised to update immediately and automatic updates are rolling out. Many reported having turned automatic background updates off for core after 6.2.1 broke their websites. Users who did so will need to manually update as soon as possible. </p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 20 May 2023 21:38:08 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Sarah Gooding\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:118:\"Gutenberg Times: WordPress 6.3 roadmap and release squad, WPCampus schedule, Wayfinder and moreâWeekend Edition #254\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://gutenbergtimes.com/?p=24143\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:124:\"https://gutenbergtimes.com/wordpress-6-3-roadmap-and-release-squad-wpcampus-schedule-wayfinder-and-more-weekend-edition-254/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:24428:\"<p>Howdy, </p>\n\n\n\n<p>Hubby and I are almost settled in our new apartment, except we are still missing our furniture. They are scheduled to arrive on June 1, which would make it exactly 74 days, since they all got packed up in Sarasota. Yesterday we measured all the rooms, so we can decide where we can place the big items, and how to organize our offices. So, when I write &#8220;settled&#8221;, I mean getting accustomed to living in our neighborhood, organizing our infrastructure of daily life and using all the transportation choices, rather than being settled in the apartment. </p>\n\n\n\n<p>WordCamp Europe is coming up fast. There are a ton of Gutenberg talks on the roster this year. <a href=\"https://gutenbergtimes.com/wordcamp-europe-2023-block-editor-talks-meet-greet-contributor-day-and-more/\">I collected them all in a separate post.</a> And if you are going in person, make sure we connect and have a chat. You can <a href=\"https://twitter.com/bph\">DM me on Twitter</a>, s<a href=\"mailto:pauli@gutenbergtimes.com\">end an email </a>or just pick a <a href=\"https://calendly.com/pauli-haack/wordcamp-europe?month=2023-06\">slot from the public calendar.</a> </p>\n\n\n\n<p>I am excited about exploring the city a couple of days prior to Contributor Day. </p>\n\n\n\n<p>This Weekend edition is again full of updates on the open-source projects, tutorials, and videos. Hope y&#8217;all enjoy it. </p>\n\n\n\n<p>Have a lovely weekend! </p>\n\n\n\n<p>Yours, đ<br /><em>Birgit</em></p>\n\n\n\n\n<div class=\"wp-block-group has-light-background-background-color has-background is-layout-flow wp-block-group-is-layout-flow\"><div class=\"wp-block-group__inner-container\">\n<p><strong>Table of Contents</strong></p>\n\n\n\n<div class=\"wp-block-sortabrilliant-guidepost\"><ul><li><a href=\"https://gutenbergtimes.com/feed/#0-word-press-release-information\">Developing Gutenberg and WordPress</a></li><li><a href=\"https://gutenbergtimes.com/feed/#0-p\">Plugins, Themes, and Tools for #nocode site builders and owners</a></li><li><a href=\"https://gutenbergtimes.com/feed/#2-word-press-6-0-1-and-6-1-scheduled\">Theme Development for Full Site Editing and Blocks</a></li><li><a href=\"https://gutenbergtimes.com/feed/#3-building-themes-for-fse-and-word-press\">Building Blocks and Tools for the Block editor. </a></li></ul></div>\n</div></div>\n\n\n\n\n\n<div class=\"ngl-articles colored ngl-articles-30_70 ngl-articles-frontend\">\n\n	\n	<div class=\"ngl-articles-wrap ngl-articles-webview\">\n	\n						\n			<div class=\"ngl-article-mobile\">\n				<table width=\"100%\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\">\n					<tr>\n						<td valign=\"top\">\n							<div class=\"ngl-article-mob-wrap\">\n							<div class=\"ngl-article-featured\"><a href=\"https://gutenbergtimes.com/wordcamp-europe-2023-block-editor-talks-meet-greet-contributor-day-and-more/\" target=\"_self\" rel=\"\"><img src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2023/05/Guiseppe-Milo-Athens-Greece-web.jpg?w=652&ssl=1\" /></a></div><div class=\"ngl-article-title\"><a href=\"https://gutenbergtimes.com/wordcamp-europe-2023-block-editor-talks-meet-greet-contributor-day-and-more/\" target=\"_self\" rel=\"\"><span>WordCamp Europe 2023 &#8211; Block editor talks, meet &#038; greet, Contributor Day and more</span></a></div><div class=\"ngl-article-excerpt\">WordCamp Europe is less than four weeks away, the speakers and sessions have been announced, and the schedule is now available. Time to make plans. <a href=\"https://gutenbergtimes.com/wordcamp-europe-2023-block-editor-talks-meet-greet-contributor-day-and-more/\" class=\"ngl-article-read-more\" target=\"_self\">Read more.</a></div>							</div>\n						</td>\n					</tr>\n				</table>\n			</div>\n			\n			\n			\n\n		\n		\n		</div>\n\n</div>\n\n\n\n\n<h2 class=\"wp-block-heading\" id=\"0-word-press-release-information\">Developing Gutenberg and WordPress</h2>\n\n\n\n<p><a href=\"https://make.wordpress.org/core/2023/05/18/roadmap-to-6-3/\"><strong>The Roadmap for the WordPress 6.3 release</strong></a> has been published. Anne McCarthy identified three focus areas for this release: </p>\n\n\n\n<ul>\n<li>Polishing the Site Editor,</li>\n\n\n\n<li>Iterating on blocks, </li>\n\n\n\n<li>Expanding patterns</li>\n\n\n\n<li>Stabilizing usability and prioritizing refinement,</li>\n\n\n\n<li>Enhancing design tools,</li>\n\n\n\n<li>Leveling up APIs,</li>\n\n\n\n<li>Addressing&nbsp;PHP&nbsp;items (8.x compatibility), and </li>\n\n\n\n<li>Performance</li>\n</ul>\n\n\n\n<p>For each focus area, she described the scope and listed GitHub issues and PRs of the work in progress. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>On the heals for the Roadmap, <strong>Hector Prieto</strong> published an update on the <a href=\"https://make.wordpress.org/core/2023/05/18/wordpress-6-3-planning-roundup/\"><strong>WordPress 6.3 Planning Roundup</strong></a>, confirming the release scheduled as it was proposed earlier and announcing Matias Ventura as the release lead and all other members of the release squad. </p>\n\n\n\n<ul>\n<li>Beta 1 will be on June 27, 2023</li>\n\n\n\n<li>Release Candidate 1 + Dev Notes are scheduled for July 18th, 2023</li>\n\n\n\n<li>General release aimed for August 8th, 2023. </li>\n</ul>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>During the latest Hallway Hangout, contributors discussed what is in the works for the Site Editor and what can be expected for WordPress 6.3. Anne McCarty posted a summary and shared the video recording in <strong> <a href=\"https://make.wordpress.org/test/2023/05/11/hallway-hangout-lets-chat-about-the-site-editor-6-3/\">Hallway Hangout: Letâs chat about the Site Editor &amp; 6.3</a></strong>. </p>\n\n\n\n<p><strong>The next Hallway Hangout is scheduled for May 25, 2023 &#8211; 17:00 UTC. Nick Diego and Justin Tadlock will be discussing <a href=\"https://make.wordpress.org/themes/2023/05/18/hallway-hangout-curating-the-editor-and-building-block-themes-for-clients/\">Curating the editor and building block themes for clients</a>. </strong>Don&#8217;t miss it. <a href=\"https://www.meetup.com/learn-wordpress-online-workshops/events/293612715/\">RSVP via Meetup.com</a></p>\n\n\n\n<a href=\"https://www.meetup.com/learn-wordpress-online-workshops/events/293612715/\"><img /></a>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>In his <a href=\"https://make.wordpress.org/design/2023/05/08/design-share-apr-24-may-5/\"><strong>Design Share: Apr 24âMay 5</strong></a>, Joen Asmussen shared what the WordPress design team has been working on the last two weeks. He lists quite a few avenues with their respective GitHub PR/Issue links, so you can follow along and chime in. </p>\n\n\n\n<ul>\n<li>Document title &#8211; as part of the re-introduction content editing to the site editor, a short video shows the switch in the UI for either editing the template or the single page, that is using the template</li>\n\n\n\n<li>Revision History Management &#8211; explores a potential future side by side page comparison</li>\n\n\n\n<li>Vertical Text as a new design tool introduced to certain blocks</li>\n\n\n\n<li>Featured ImageÂ improvements &#8211; show a more compact and streamlined interface to handle feature images settings</li>\n</ul>\n\n\n\n<img />\n\n\n\n<p><strong>Justin Tadlock</strong> published the monthly roundup <a href=\"https://developer.wordpress.org/news/2023/05/whats-new-for-developers-may-2023/\"><strong>Whatâs new for developers? (May 2023)</strong></a> on the developer blog. It&#8217;s again full of focused notes about changes in the WordPress worlds relevant for extenders, plugin and theme builders and agency or freelance developers building sites for others.  </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Anne McCarthy </strong>published the next <strong><a href=\"https://make.wordpress.org/test/2023/05/18/fse-program-testing-call-23-rapid-revamp/\">FSE Program Testing Call #23: Rapid Revamp</a>.</strong> &#8220;With the&nbsp;<a href=\"https://make.wordpress.org/core/2023/05/18/roadmap-to-6-3/\">roadmap to 6.3 published</a>&nbsp;and another version of&nbsp;Gutenberg&nbsp;out in the wild, itâs time to test some of the upcoming features that are in the works to upgrade and polish the experience of using the Site Editor:&#8221; she wrote and listed all eight of them. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>Led by <strong>Fabian KĂ€gy</strong>, <strong>Gutenberg 15.8</strong> was released on May 18th, 2023. The number of PRs merged for this release was considerably higher than for 15.7 and it&#8217;s expected to rise with the urgency of the upcoming WordPress 6.3 release. There are only three Gutenberg plugins releases left until Beta 1 on June 27. </p>\n\n\n\n<ul>\n<li>15.9 scheduled for May 31</li>\n\n\n\n<li>16.0 to be released on Jun 14 (after WordCamp Europe) </li>\n\n\n\n<li>16.1 RC 1 to be release on June 21</li>\n</ul>\n\n\n\n<p>In his release post <a href=\"https://make.wordpress.org/core/2023/05/20/whats-new-in-gutenberg-15-8-may-17/\">Whatâs new in Gutenberg 15.8? (May 17)</a>, KĂ€gy highlight three new features that need testing from Gutenberg plugin users: </p>\n\n\n\n<ul>\n<li><a href=\"https://make.wordpress.org/core/2023/05/17/whats-new-in-gutenberg-15-8-may-17/#add-the-pages-menu-to-the-site-editor-50463\">Add the pages menu to the site editor</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2023/05/17/whats-new-in-gutenberg-15-8-may-17/#add-revisions-ui-50089\">Add revisions UI to the global styles interface</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2023/05/17/whats-new-in-gutenberg-15-8-may-17/#add-theme-previews-for-block-themes-50030\">Add Theme Previews for block themes</a></li>\n\n\n\n<li>One feature is now still listed in experiments. It will come out next Gutenberg plugin release: The Command Center AKA Wayfinder. (See Riad Benguella&#8217;s post. )</li>\n</ul>\n\n\n\n<p>It&#8217;s always a great pleasure to connect with <strong>Fabian KĂ€gy</strong>. We had a great time geeking out over the blog editor while recording episode 83 of the Gutenberg Changelog. We discussed Gutenberg 15.7, 15.8 the feature available on the Experiments page and 6.2.1, Gutenberg Storybook and 10up tools. The episode  is at the editor now, and it will arrive in your favorite podcast app over the weekend. </p>\n\n\n\n<img />\n\n\n\n<div class=\"wp-block-group has-light-background-background-color has-background is-layout-flow wp-block-group-is-layout-flow\"><div class=\"wp-block-group__inner-container\">\n<p><strong>đïž </strong> New episode:  <a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-82-gutenberg-15-6-and-proposed-schedule-for-wordpress-6-3/\">Gutenberg Changelog #82 â Gutenberg 15.6 and proposed schedule for WordPress 6.3</a> with Birgit Pauli-Haack and special guest Nick Diego</p>\n</div></div>\n\n\n\n<p><strong><a href=\"https://twitter.com/riadbenguella\">Riad Benguella</a></strong> published the post <a href=\"https://make.wordpress.org/core/2023/05/17/command-center-request-for-feedback/\"><strong>C</strong></a><strong><a href=\"https://make.wordpress.org/core/2023/05/17/command-center-request-for-feedback/\">ommand Center: Request for feedback</a> </strong>asking for testing and review of a new feature that will come out of the experimental phase for Gutenberg 15.9, for now called the Command Center, and the Marketing team is probably recommending a new name: The<strong> Wayfinder. </strong></p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"0-p\">Plugins, Themes, and Tools for #nocode site builders and owners</h2>\n\n\n\n<p><strong>Caroline Nymark</strong> published an <a href=\"https://fullsiteediting.com/site-creators/introduction-to-the-site-editor/\"><strong>Introduction to the Site Editor for creators</strong>.</a> This tutorial is meant for Beginners and no-code creators and covers everything available since WordPress 6.2 and Gutenberg 15.7. Although it&#8217;s title Introduction, it is quite comprehensive and covers the Site Editor, Navigation, Styles, Templates and Template parts. Then she dives deeper into the Design Tools via the Styles menu item. You will be creating or modifying themes in no time! </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><a href=\"https://wordpress.org/plugins/maxi-blocks/\"><strong>Maxi Blocks</strong></a> â a template library for site builders using  WordPress Block editor. It came recently out of beta and offers developers a whole range of design tools in an interface that has been built on top of Gutenberg, yet using custom components to offer additional design features. The plugin comes with hundreds of icons, patterns, templates and sixteen custom blocks. The Pro version is available at <a href=\"https://maxiblocks.com/\">MaxiBlocks.com</a>. It&#8217;s meant for designers looking for all the tools, not so much for beginners or site owners. There will be a learning curve due to the additional UI components. </p>\n\n\n\n<img />\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong><a href=\"https://twitter.com/mahdiali_\">MahdiAli Khanusiya</a> </strong>built the plugin<strong> </strong><a href=\"https://wordpress.org/plugins/patternswp/\"><strong>PatternWP</strong></a> &#8211; a pattern block library for WordPress. The first version offers patterns on many categories. for the busy site owner. The plan is to be adding new patterns and templates on a consistent basis. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<h2 class=\"wp-block-heading\" id=\"2-word-press-6-0-1-and-6-1-scheduled\">Theme Development for Full Site Editing and Blocks</h2>\n\n\n\n<p>Lots of feedback has been provided during the Call for Exploration. <strong>Anne McCarthy </strong>published <a href=\"https://make.wordpress.org/test/2023/05/04/fse-program-build-a-block-theme-summary/\"><strong>FSE Program Build a Block Theme Summary</strong></a>. The TL;DR: &#8220;Using the Site Editor alongside the Create Block Theme plugin supercharges the experience, mainly by filling in gaps around font management and offering more nuanced creating/exporting options. With these added features, the Site Editor is both left to shine as a theme building tool and the current known pain points impacting regular site building come to the surface, like needing more clarity around where layers of styles are coming from. In general, feedback fell into three categories: Create Block Theme plugin pain points, missing options in the Site Editor (font management, synced patterns, desire for more styling options with certain blocks), andÂ UXÂ considerations for the Site Editor that match the site building experience. &#8221; she wrote. The videos shared from the contributors are certainly eye-opening. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong><a href=\"https://twitter.com/mikemcalister\">Mike McAlister</a></strong> explains in his article how <a href=\"https://olliewp.com/a-native-and-iterative-approach-to-responsive-control-in-wordress/\"><strong>a native and iterative approach to responsive control in WordPress</strong></a> could bridge the gap between the goals to rely on <a href=\"https://developer.wordpress.org/news/2023/02/intrinsic-design-theming-and-rethinking-how-to-design-with-wordpress/\">i<em>ntrinsic design</em></a> and still be able to handle edge cases for viewpoint-driven responsiveness of a site. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>In his video, <a href=\"https://www.youtube.com/watch?v=Zh0ANsYgoN0\"><strong>WordPress Gutenberg Product Manager explains what&#8217;s next for Responsive Websites and Block Themes</strong></a>,  <strong>Jamie Marsland</strong> interviewed <strong>Rich Tabor</strong> on intrinsic design, what a theme product might look like for theme creators and what the next wave of block building inspiration might arrive at the WordPress shores. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong><a href=\"https://twitter.com/jkoussertari\">James Koussertari</a></strong> explained <a href=\"https://gutenbergmarket.com/news/using-layout-sizes-in-themejson\"><strong>Using Layout Sizes in theme.json</strong></a>. &#8220;The layout setting in theme.json is great for developers, as they can set default container sizes for their design system, easily in one place. It also means that content editors do not have to think about which container sizes to set manually each time they add a block.&#8221; he wrote on the blog of the Gutenberg Market</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>The latest call for testing ended last week, too and <strong>Anne McCarthy</strong> recounts the feedback: <a href=\"https://make.wordpress.org/test/2023/05/11/fse-program-front-page-fun-summary/\"><strong>FSE Program Front Page Fun Summary</strong></a>. The high-level feedback revealed: &#8220;In general, the call for testing was relatively tame bug wise, with only a few obvious ones found, mainly in the NavigationÂ block. The usability feedback related to many ongoing projects in the Site Editor underscoring the impact of solving these consistent problems, in particularÂ the clarification of the content &lt;> template relationshipÂ and confusion around theÂ overall experience of managing pieces of navigation.Â &#8221; and &#8220;While the new Grid layout type was the primary focus of the testing call, feedback on it was limited to suggestions for consolidating the various options between the grid layout, Columns block, Gallery block, and Table block.&#8221; McCarthy wrote. </p>\n\n\n\n\n<p><strong>&nbsp;<a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/\" target=\"_blank\" rel=\"noreferrer noopener\">&#8220;Keeping up with Gutenberg &#8211; Index 2022&#8221;</a>&nbsp;</strong><br />A chronological list of the WordPress Make Blog posts from various teams involved in Gutenberg development: Design, Theme Review Team, Core Editor, Core JS, Core CSS, Test and Meta team from Jan. 2021 on. Updated by yours truly.  <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2020/\"><em>The index 2020 is here</em></a></p>\n\n\n\n\n<h2 class=\"wp-block-heading\" id=\"3-building-themes-for-fse-and-word-press\">Building Blocks and Tools for the Block editor. </h2>\n\n\n\n<p><strong><a href=\"https://twitter.com/3LPU4S\">Alfredo Navas</a></strong>, WebDevStudios was <a href=\"https://webdevstudios.com/2023/05/16/query-loop-block/\"><strong>Having Fun with Query Loop Block</strong></a> and published a post to tell you all about it. He takes you along to explore the usefulness of the Query Loop block and learn how to extend its capabilities.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>In his latest post for the Developer Blog, <strong>Michael Burridge</strong> created a tutorial on  <a href=\"https://developer.wordpress.org/news/2023/05/useentityrecords-an-easier-way-to-fetch-wordpress-data/\"><strong>useEntityRecords: an easier way to fetch WordPress data</strong></a>. If you have simple data fetching requirements and donât need additional customization or resolution checks,Â the <code>useEntityRecords</code> function can be a straightforward choice. Burridge shows  how it simplifies data handling in contrast to useSelect + getEntityRecords. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>Don&#8217;t miss next week&#8217;s <strong>Developer Hours</strong> about the new WordPress tool called Playground. <strong>Adam ZieliĆski</strong> will introduce the app and demo some great use cases for it. There are two events, so all timezones get a chance to participate live. </p>\n\n\n\n<ul>\n<li><a href=\"https://www.meetup.com/learn-wordpress-online-workshops/events/293196462/\">May 23, 2023, at 17:00 UTC (11 am EDT)</a></li>\n\n\n\n<li><a href=\"https://www.meetup.com/learn-wordpress-online-workshops/events/293196452/\">May 24, 2023, at 8 am UTC </a></li>\n</ul>\n\n\n\n<img />\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p><strong>WPCampus </strong>will take place from July 12 to the 14th, 2023 in New Orleans. The organizing team released their <a href=\"https://2023.wpcampus.org/schedule/\">schedule.</a> WPCampus 2023 is a hybrid event.Â <strong><a href=\"https://2023.wpcampus.org/tickets/\">Join in-person or online</a>.</strong></p>\n\n\n\n<p>I spotted Nick Diego on the roster with his 3-hour Workshop: <a href=\"https://2023.wpcampus.org/schedule/workshops/modern-wordpress-building-techniques-full-site-editing-in-higher-ed/\"><strong>Modern WordPress Building Techniques: Full Site Editing in Higher Ed</strong></a>. </p>\n\n\n\n<p>But there is more: </p>\n\n\n\n<ul>\n<li>Daniel Tyger and Tom O&#8217;Donnell from the University of Maine will share their Journey <a href=\"https://2023.wpcampus.org/schedule/from-classic-to-blocks-in-90-days/\"><strong>From Classic to Blocks in 90 Days</strong></a>?</li>\n\n\n\n<li>Joni Halabi will present on <a href=\"https://2023.wpcampus.org/schedule/make-it-your-own-integrating-twig-templates-with-your-wordpress-block-theme/\"><strong>Make it your own: Integrating Twig templates with your WordPress block theme</strong></a></li>\n\n\n\n<li><a href=\"https://2023.wpcampus.org/schedule/development-of-a-no-code-theme-for-teaching-full-site-editing-to-beginning-wordpress-students/\"><strong>Development of a No-Code Theme for Teaching Full Site Editing to Beginning WordPress Students</strong></a> with Drake GĂłmez</li>\n\n\n\n<li><a href=\"https://2023.wpcampus.org/schedule/destination-full-site-editing-all-the-steps-monmouth-university-took-to-prepare-the-future-of-wordpress/\"><strong>Destination Full-Site Editing: All the Steps Monmouth University Took to Prepare the Future of WordPress</strong></a> with <strong>Steve Graboski</strong></li>\n\n\n\n<li><a href=\"https://2023.wpcampus.org/schedule/55330/\"><strong>Developing a design system within the block editor</strong></a> with <strong>Nick Novak</strong></li>\n\n\n\n<li></li>\n</ul>\n\n\n\n\n<p><strong><a href=\"https://gutenbergtimes.com/need-a-zip-from-master/\">Need a plugin .zip from Gutenberg&#8217;s master branch?</a></strong><br />Gutenberg Times provides daily build for testing and review. <br />Have you been using it? Hit reply and let me know.</p>\n\n\n\n<p><img alt=\"GitHub all releases\" src=\"https://img.shields.io/github/downloads/bph/gutenberg/total?style=for-the-badge\" /></p>\n\n\n\n\n<p class=\"has-text-align-right has-small-font-size\"><em>Questions? Suggestions? Ideas? Don&#8217;t hesitate to send <a href=\"mailto:pauli@gutenbergtimes.com\">them via email</a> or send me a message on WordPress Slack or Twitter @bph</em>. </p>\n\n\n\n<p class=\"has-text-align-right has-small-font-size\">For questions to be answered on the <a href=\"http://gutenbergtimes.com/podcast\">Gutenberg Changelog</a>, send them to <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n\n<p>Featured Image: Colorful Duplo blocks by Maruska, <a href=\"https://wordpress.org/photos/photo/2206266bbc/\">found on WordPress Photos site.</a></p>\n\n\n\n<hr class=\"wp-block-separator has-css-opacity is-style-wide\" />\n\n\n\n<p class=\"has-text-align-left\"><strong>Don&#8217;t want to miss the next Weekend Edition? </strong></p>\n\n\n\n<form class=\"wp-block-newsletterglue-form ngl-form ngl-portrait\" action=\"https://gutenbergtimes.com/feed/\" method=\"post\"><div class=\"ngl-form-container\"><div class=\"ngl-form-field\"><label class=\"ngl-form-label\" for=\"ngl_email\"><br />Type in your Email address to subscribe.</label><div class=\"ngl-form-input\"><input type=\"email\" class=\"ngl-form-input-text\" name=\"ngl_email\" id=\"ngl_email\" /></div></div><button type=\"submit\" class=\"ngl-form-button\">Subscribe</button><p class=\"ngl-form-text\">We hate spam, too and won&#8217;t give your email address to anyone except Mailchimp to send out our Weekend Edition</p></div><div class=\"ngl-message-overlay\"><div class=\"ngl-message-svg-wrap\"></div><div class=\"ngl-message-overlay-text\">Thanks for subscribing.</div></div><input type=\"hidden\" name=\"ngl_list_id\" id=\"ngl_list_id\" value=\"26f81bd8ae\" /><input type=\"hidden\" name=\"ngl_double_optin\" id=\"ngl_double_optin\" value=\"yes\" /></form>\n\n\n\n<hr class=\"wp-block-separator has-css-opacity is-style-wide\" />\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 20 May 2023 13:00:34 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Birgit Pauli-Haack\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:52:\"WordPress.org blog: WordPress 6.2.2 Security Release\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=14974\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:68:\"https://wordpress.org/news/2023/05/wordpress-6-2-2-security-release/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:5345:\"<h2 class=\"wp-block-heading\">WordPress 6.2.2 is now available!</h2>\n\n\n\n<p>The 6.2.2 minor release addresses <a href=\"https://core.trac.wordpress.org/query?milestone=6.2.2&col=id&col=summary&col=status&col=owner&col=type&col=priority&col=milestone&order=priority\">1 bug</a> and 1 security issue. Because this is a security release, it is recommended that you update your sites immediately. All versions since WordPress 5.9 have also been updated.</p>\n\n\n\n<p>WordPress 6.2.2 is a rapid response release to address a regression in 6.2.1 and further patch a vulnerability addressed in 6.2.1. The next major release will be<a href=\"https://make.wordpress.org/core/6-3/\"> version 6.3</a> planned for August 2023.</p>\n\n\n\n<p>The update process will begin automatically if you have sites that support automatic background updates.</p>\n\n\n\n<p>You can <a href=\"https://wordpress.org/wordpress-6.2.2.zip\">download WordPress 6.2.2 from WordPress.org</a> or visit your WordPress Dashboard, click âUpdates,â and click âUpdate Now.â</p>\n\n\n\n<p>For more information on this release, please <a href=\"https://wordpress.org/support/wordpress-version/version-6-2-2\">visit the HelpHub site</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Security updates included in this release</strong></h2>\n\n\n\n<p>The security team would like to thank the following people for responsibly reporting vulnerabilities and allowing them to be fixed in this release.&nbsp;</p>\n\n\n\n<ul>\n<li>Block themes parsing shortcodes in user-generated data; thanks to Liam Gladdy of<a href=\"https://wpengine.com/\"> WP Engine</a> for reporting this issue.</li>\n</ul>\n\n\n\n<p>The issue above was originally patched in the 6.2.1 release, but needed further hardening here in 6.2.2. The Core team is thankful for the community in their response to 6.2.1 and collaboration on finding the best path forward for proper resolution in 6.2.2. The folks who worked on 6.2.2 are especially appreciative for everyoneâs understanding while they worked asynchronously to get this out the door as quickly as possible.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Thank you to these WordPress contributors</h2>\n\n\n\n<p>This release was led by <a href=\"https://profiles.wordpress.org/desrosj/\">Jonathan Desrosiers</a>.</p>\n\n\n\n<p>WordPress 6.2.2 would not have been possible without the contributions of the following people. Their asynchronous coordination to deliver security fixes into a stable release is a testament to the power and capability of the WordPress community.</p>\n\n\n\n<p><a href=\"https://profiles.wordpress.org/jorbin/\">Aaron Jorbin</a>, <a href=\"https://profiles.wordpress.org/xknown/\">Alex Concha</a>, <a href=\"https://profiles.wordpress.org/antpb/\">Anthony Burchell</a>, <a href=\"https://profiles.wordpress.org/cbringmann/\">Chloe Bringmann</a>, <a href=\"https://profiles.wordpress.org/chriscct7/\">chriscct7</a>, <a href=\"https://profiles.wordpress.org/talldanwp/\">Daniel Richards</a>, <a href=\"https://profiles.wordpress.org/davidbaumwald/\">David Baumwald</a>, <a href=\"https://profiles.wordpress.org/ehtis/\">Ehtisham S.</a>, <a href=\"https://profiles.wordpress.org/gziolo/\">Greg ZiĂłĆkowski</a>, <a href=\"https://profiles.wordpress.org/isabel_brison/\">Isabel Brison</a>, <a href=\"https://profiles.wordpress.org/audrasjb/\">Jb Audras</a>, <a href=\"https://profiles.wordpress.org/jeffpaul/\">Jeffrey Paul</a>, <a href=\"https://profiles.wordpress.org/johnbillion/\">John Blackbourn</a>, <a href=\"https://profiles.wordpress.org/desrosj/\">Jonathan Desrosiers</a>, <a href=\"https://profiles.wordpress.org/chanthaboune/\">Josepha</a>, <a href=\"https://profiles.wordpress.org/Clorith/\">Marius L. J.</a>, <a href=\"https://profiles.wordpress.org/matveb/\">Matias Ventura</a>, <a href=\"https://profiles.wordpress.org/mikeschroder/\">Mike Schroder</a>, <a href=\"https://profiles.wordpress.org/peterwilsoncc/\">Peter Wilson</a>, <a href=\"https://profiles.wordpress.org/youknowriad/\">Riad Benguella</a>, <a href=\"https://profiles.wordpress.org/noisysocks/\">Robert Anderson</a>, <a href=\"https://profiles.wordpress.org/rmccue/\">Ryan McCue</a>, <a href=\"https://profiles.wordpress.org/Otto42/\">Samuel Wood (Otto)</a>, <a href=\"https://profiles.wordpress.org/coffee2code/\">Scott Reilly</a>, and <a href=\"https://profiles.wordpress.org/timothyblynjacobs/\">Timothy Jacobs</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">How to contribute</h2>\n\n\n\n<p>To get involved in WordPress core development, head over to Trac, <a href=\"https://core.trac.wordpress.org/report/6\">pick a ticket</a>, and join the conversation in the <a href=\"https://wordpress.slack.com/archives/C02RQBWTW\">#core</a> and <a href=\"https://wordpress.slack.com/archives/C051Z1SKBDZ\">#6-3-release-leads</a> channels. Need help? Check out the <a href=\"https://make.wordpress.org/core/handbook/\">Core Contributor Handbook</a>.</p>\n\n\n\n<p><em>Thanks to <a href=\"https://profiles.wordpress.org/cbringmann/\" class=\"mention\"><span class=\"mentions-prefix\">@</span>cbringmann</a>, <a href=\"https://profiles.wordpress.org/davidbaumwald/\" class=\"mention\"><span class=\"mentions-prefix\">@</span>davidbaumwald</a>, <a href=\"https://profiles.wordpress.org/chanthaboune/\" class=\"mention\"><span class=\"mentions-prefix\">@</span>chanthaboune</a>, <a href=\"https://profiles.wordpress.org/jeffpaul/\" class=\"mention\"><span class=\"mentions-prefix\">@</span>jeffpaul</a> for proofreading.</em></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 20 May 2023 04:09:39 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:19:\"Jonathan Desrosiers\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:75:\"WPTavern: WordPress 6.3 Development Kicks Off to Conclude Gutenberg Phase 2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:30:\"https://wptavern.com/?p=145206\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:86:\"https://wptavern.com/wordpress-6-3-development-kicks-off-to-conclude-gutenberg-phase-2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:3694:\"<p>The WordPress 6.3 development cycle has begun and work is already underway  on an ambitious list of features that will debut in the upcoming major release. It will <a href=\"https://make.wordpress.org/core/2023/02/04/phase-2-finale/\">cap off Phase 2</a> of the Gutenberg project, with an emphasis on polishing customization features and making them easier to use.</p>\n\n\n\n<p>WordPress 6.3 Editor Triage co-lead Anne McCarthy published a <a href=\"https://make.wordpress.org/core/2023/05/18/roadmap-to-6-3/\">roadmap to 6.3</a> this week, which summarizes what users can expect:</p>\n\n\n\n<blockquote class=\"wp-block-quote\">\n<p>This release aims to make it easier for users to edit pages, manage navigation, and adjust styles all directly in the Site Editor. It also seeks to provide detailed, relevant information when exploring different parts of the site, such as showing the number of posts per page when viewing relevantÂ blogÂ templates. </p>\n</blockquote>\n\n\n\n<p>In addition to polishing and wrapping up phase 2, McCarthy&#8217;s post outlines the new features that are coming. Here are a few of the highlights: </p>\n\n\n\n<ul>\n<li><a href=\"https://github.com/WordPress/gutenberg/issues/44461\">Introduce content editing</a>, including clarifying the relationship between templates and content.</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/issues/50396\">Add a Navigation section to the Site Editor</a>&nbsp;with nuanced options depending on the number of menus and complexity of each.</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/50463\">Add a Pages section to the Site Editor</a>.&nbsp;</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/49014\">Add a Styles section to the Site Editor.</a>&nbsp;</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/issues/49601\">Expose revisions (styles, templates, and template parts)</a>.</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/issues/48457\">Add a command center tool</a>Â for easily accessing different parts of your site.Â <a href=\"https://make.wordpress.org/core/2023/05/17/command-center-request-for-feedback/\">More information here</a>.</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/50030\">Add Theme Previews for block themes</a>.</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/issues/38990\">Surface aspect ratio tooling</a>.</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/issues/49175\">Consider adding distraction free mode to Site Editor</a>.&nbsp;</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/issues/25071\">Keep custom templates and template parts across themes</a>.</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/issues/45271\">Add an interface for font management</a>.</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/issues/50397#top\">Explore a path towards âlibraryâ management with reusable blocks and template parts</a>.</li>\n</ul>\n\n\n\n<p>This is a tentative glimpse at some of the user-facing features that may be coming in WordPress 6.3, but the <a href=\"https://make.wordpress.org/core/2023/05/18/roadmap-to-6-3/\">roadmap</a> includes many more items, screenshots, and quick demos.</p>\n\n\n\n<p>&#8220;As always, whatâs shared here is being actively pursued, but doesnât necessarily mean each will make it into the final release of WordPress 6.3,&#8221; McCarthy said.</p>\n\n\n\n<p>Gutenberg Lead Architect MatĂ­as Ventura will be <a href=\"https://make.wordpress.org/core/2023/05/18/wordpress-6-3-planning-roundup/\">leading WordPress 6.3</a>. Beta 1 is expected in a little more than a month on June 27, 2023, with RC 1 on July 18, and the general release scheduled for August 8.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 19 May 2023 22:13:07 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Sarah Gooding\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"WPTavern: WCEU 2023 Publishes Schedule, Reaffirms Commitment to Diversity\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:30:\"https://wptavern.com/?p=145217\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"https://wptavern.com/wceu-2023-publishes-schedule-reaffirms-commitment-to-diversity\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:3577:\"<p><a href=\"https://europe.wordcamp.org/2023/\">WordCamp Europe</a> 2023 is just under three weeks away from happening in Athens on June 8-10. More than 2,700 <a href=\"https://europe.wordcamp.org/2023/tickets/\">tickets</a> have been purchased and 527 remain, along with 49 micro-sponsor tickets. </p>\n\n\n\n<p>Speaker announcements have concluded and the official <a href=\"https://europe.wordcamp.org/2023/schedule/\">schedule</a> was published today. WCEU will be running three tracks of presentations and two tracks for workshops. Organizers have also announced a <a href=\"https://europe.wordcamp.org/2023/welness-track-activities/\">Wellness Track</a> that will feature different activities throughout the day, including a Yoga class, a Tai Chi class, and a group hike.</p>\n\n\n\n<p>&#8220;TheÂ WellnessÂ Track is an important addition to WordCamp Europe because we need to find a balance and be more focused on taking care of our minds and bodies, taking care of the whole community and in turn the one world we have to live in,&#8221; organizer Ohia Thompson said. </p>\n\n\n\n<p>&#8220;This means seeing our interconnectedness and moving forward with a focus on wellbeing, diversity, and sustainability. TheÂ WellnessÂ Track this year is just the beginning of a more intentional future for everyone connected to WordPress.â</p>\n\n\n\n<p>Last year the team hosting the event in Porto was <a href=\"https://europe.wordcamp.org/2022/diversity-at-wceu/\">called out for a lack of diversity on the organizing team</a>, which performs critical tasks like selecting speakers and managing a speaker support program. In what appears to be an echo back to that controversy, a public interaction on Twitter earlier this month caused community members to question the organizing team.</p>\n\n\n\n<p>WCEU was once again forced to reaffirm its commitment to diversity after Sjoerd Blom, one of the Global organizers, accused StellarWP&#8217;s Director of Community Engagement, Michelle Frechette, of &#8220;being prejudiced&#8221; when she questioned the lack of diversity in the first few rounds of speaker announcements. </p>\n\n\n\n<div class=\"wp-block-embed__wrapper\">\n<blockquote class=\"twitter-tweet\"><p lang=\"en\" dir=\"ltr\">Please stop being prejudiced and wait until ALL speakers have been announced. Thanks.</p>&mdash; Sjoerd Blom (@sjblom) <a href=\"https://twitter.com/sjblom/status/1656015637641043968?ref_src=twsrc%5Etfw\">May 9, 2023</a></blockquote>\n</div>\n\n\n\n<p>Blom has since publicly apologized for his response to the criticism this week, reiterating that diversity matters to the team, but only after WCEU received overwhelmingly negative feedback regarding the incident.</p>\n\n\n\n<div class=\"wp-block-embed__wrapper\">\n<blockquote class=\"twitter-tweet\"><p lang=\"en\" dir=\"ltr\">In past weeks, <a href=\"https://twitter.com/michelleames?ref_src=twsrc%5Etfw\">@michelleames</a> highlighted the lack of diversity in WCEUâs speaker line up. Iâm truly sorry for the offense I caused, especially in using the word âprejudicedâ. <a href=\"https://twitter.com/hashtag/WCEU?src=hash&ref_src=twsrc%5Etfw\">#WCEU</a> and I know that diversity matters, and we will be sharing more about what happened in coming days.</p>&mdash; Sjoerd Blom (@sjblom) <a href=\"https://twitter.com/sjblom/status/1659236811456086016?ref_src=twsrc%5Etfw\">May 18, 2023</a></blockquote>\n</div>\n\n\n\n<p>WordCamp Europe has not yet published anything to mitigate the effects of this public altercation but damage control measures are likely in the works, as Blom indicated a more official response will be coming from the team.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 19 May 2023 17:23:12 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Sarah Gooding\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:68:\"Do The Woo Community: Do the Woo Friday Show with Michelle Frechette\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"https://dothewoo.io/?p=75166\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:67:\"https://dothewoo.io/do-the-woo-friday-show-with-michelle-frechette/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:390:\"<p>We have a great conversation of tips and experiences when it comes to speaking at WordPress events. </p>\n<p>&gt;&gt; The post <a rel=\"nofollow\" href=\"https://dothewoo.io/do-the-woo-friday-show-with-michelle-frechette/\">Do the Woo Friday Show with Michelle Frechette</a> appeared first on <a rel=\"nofollow\" href=\"https://dothewoo.io\">Do the Woo - a WooCommerce Builder Community</a>	.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 19 May 2023 08:01:51 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"BobWP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:106:\"Post Status: WP 6.2.1 âą PHP8 Compatibility âą Translation Playground âą Contributor Mentorship Program\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://poststatus.com/?p=149361\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:105:\"https://poststatus.com/wp-6-2-1-php8-compatibility-translation-playground-contributor-mentorship-program/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:18457:\"<h2 class=\"wp-block-heading\" id=\"h-this-week-at-wordpress-org-april-3-2023\">This Week at WordPress.org (May 14, 2023)</h2>\n\n\n<div class=\"has-background has-theme-palette-8-background-color wp-block-post-excerpt\"><p class=\"wp-block-post-excerpt__excerpt\">It&#8217;s time to update your WordPress websites now. This week&#8217;s release breaks shortcodes used in Block Themes on Templates, but is related to a security issue. <br /><br />Is WordPress, and the plugin and theme ecosystem around it, ready for PHP 8? Earlier versions of PHP, such as 7.4, are now considered End of Life, and hosts are eager to deploy supported versions. But first, Core compatibility needs additional testing to come out of beta compatibility.<br /><br />Translating WordPress just got a little bit easier for contributors with the WP Translation Playground. <br /><br />A Community team working group announces a pilot proposal for a Contributor Mentorship Program, helping all contributors onboard. </p></div>\n\n\n<div class=\"wp-block-spacer\"></div>\n\n\n\n<div class=\"wp-block-kadence-infobox kt-info-box_94d1bd-77\"><div class=\"kt-blocks-info-box-link-wrap kt-blocks-info-box-media-align-left kt-info-halign-left\"><div class=\"kt-blocks-info-box-media-container\"><div class=\"kt-blocks-info-box-media kt-info-media-animate-none\"><div class=\"kadence-info-box-icon-container kt-info-icon-animate-none\"><div class=\"kadence-info-box-icon-inner-container\"><span class=\"kb-svg-icon-wrap kb-svg-icon-ic_people kt-info-svg-icon\"></span></div></div></div></div><div class=\"kt-infobox-textcontent\"><h2 class=\"kt-blocks-info-box-title\">WP 6.2.1, PHP8, Translation Playground, Mentorship Program</h2><p class=\"kt-blocks-info-box-text\"><img src=\"https://s.w.org/images/core/emoji/14.0.0/72x72/1f680.png\" alt=\"đ\" class=\"wp-smiley\" /> <a href=\"https://wordpress.org/news/2023/05/wordpress-6-2-1-maintenance-security-release/\">WordPress 6.2.1 Maintenance &amp; Security Release</a><br /><br /><img src=\"https://s.w.org/images/core/emoji/14.0.0/72x72/1f418.png\" alt=\"đ\" class=\"wp-smiley\" /> <a href=\"https://make.wordpress.org/hosting/2023/05/15/is-wordpress-compatible-with-php-8/\">Is WordPress compatible with PHP 8?</a><br /><br /><img src=\"https://s.w.org/images/core/emoji/14.0.0/72x72/1f5e3.png\" alt=\"đŁ\" class=\"wp-smiley\" /> <a href=\"https://make.wordpress.org/polyglots/2023/04/19/wp-translation-playground/\">WP Translation Playground</a><br /><br /><img src=\"https://s.w.org/images/core/emoji/14.0.0/72x72/1f469-1f3fb-200d-1f3eb.png\" alt=\"đ©đ»âđ«\" class=\"wp-smiley\" /> <a href=\"https://make.wordpress.org/project/2023/05/17/wordpress-contributor-mentorship-program-pilot-program-proposal/\">WordPress Contributor Mentorship Program: Pilot Program Proposal</a><br /><br /> </p></div></div></div>\n\n\n\n<div class=\"wp-block-kadence-spacer aligncenter kt-block-spacer-_b57166-6e\"><div class=\"kt-block-spacer kt-block-spacer-halign-center\"><hr class=\"kt-divider\" /></div></div>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-news\"><a href=\"https://wordpress.org/news\">News</a></h2>\n\n\n\n<ul>\n<li><a href=\"https://wordpress.org/news/2023/05/wordpress-6-2-1-maintenance-security-release/\">WordPress 6.2.1 Maintenance &amp; Security Release</a></li>\n\n\n\n<li><a href=\"https://wordpress.org/news/2023/05/2022-annual-survey-results-next-steps/\">2022 Annual Survey Results &amp; Next Steps</a></li>\n\n\n\n<li><a href=\"https://wordpress.org/news/2023/05/the-month-in-wordpress-april-2023/\">The Month in WordPress â April 2023</a></li>\n\n\n\n<li><a href=\"https://wordpressfoundation.org/news/2023/kim-parsell-memorial-scholarship-for-wordcamp-us-2023/\">Kim Parsell Memorial Scholarship for WordCamp US 2023</a></li>\n</ul>\n\n\n\n<div class=\"wp-block-kadence-spacer aligncenter kt-block-spacer-_8f6276-eb\"><div class=\"kt-block-spacer kt-block-spacer-halign-center\"><hr class=\"kt-divider\" /></div></div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-3\">\n<div class=\"wp-block-column is-layout-flow\">\n<h2 class=\"wp-block-heading\"><a href=\"https://make.wordpress.org/accessibility\">Accessibility</a></h2>\n\n\n\n<ul>\n<li><a href=\"https://make.wordpress.org/accessibility/2023/05/18/accessibility-team-meeting-agenda-may-19-2023/\">Accessibility Team Meeting Agenda: May 19, 2023</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-community\"><a href=\"https://make.wordpress.org/community\">Community</a></h2>\n\n\n\n<ul>\n<li><a href=\"https://make.wordpress.org/community/2023/05/18/meetup-organizer-newsletter-may-2023/\">Meetup Organizer Newsletter: May 2023</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/community/2023/05/18/announcement-increasing-meetup-venue-support-funds/\">Announcement: Increasing Meetup Venue Support Funds</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/community/2023/05/10/kim-parsell-memorial-scholarship-for-wordcamp-us-2023/\">Kim Parsell Memor