INSERT INTO `pcta_postmeta` VALUES (380,66,'descripcion','<a href=\"http://peruconexiontravel.com\">Arequipa,</a> tambiĂ©n conocido como: ciudad blanca, <a href=\"http://peruconexiontravel.com/\">la ciudad heroica del caudillo</a>, etc. es la segunda ciudad mĂĄs grande del PerĂș, ubicada en la provincia y departamento homĂłnimos.\r\nVisitaremos la plaza de armas, una de las mĂĄs bellas del PerĂș, la Iglesia jesuita de la CompaĂ±Ă­a de JesĂșs, que en su bella fachada anuncia la denominada arquitectura mestiza, sus claustros y cĂșpula, la casona TristĂĄn del Pozo; al final, para una magnĂ­fica vista de la ciudad, visitaremos los tĂ­picos distritos de Carmen alto y Yanahuara. (Mirador e Iglesia).');
