INSERT INTO `pcta_postmeta` VALUES (390,67,'descripcion','Arequipa, tambiĂ©n conocido como: ciudad blanca, heroica ciudad de los libres de Arequipa, ciudad caudillo, etc. es la segunda ciudad mĂĄs grande del PerĂș, ubicada en la provincia y departamento homĂłnimos.\r\nVisitaremos la plaza de armas, una de las mĂĄs bellas del PerĂș, la Iglesia jesuita de la CompaĂ±Ă­a de JesĂșs, que en su bella fachada anuncia la denominada arquitectura mestiza, sus claustros y cĂșpula, la casona TristĂĄn del Pozo; al final, para una magnĂ­fica vista de la ciudad, visitaremos los tĂ­picos distritos de Carmen alto y Yanahuara. (Mirador e Iglesia).\r\n');
