INSERT INTO `pcta_postmeta` VALUES (495,76,'descripcion','Visitar Cusco es siempre una gran aventura. ImagĂ­nense recorrer sus hermosos paisajes alto andinos y las zonas mĂĄs icĂłnicas que ofrece la capital del Imperio de los Incas. Con este tour podrĂĄn hacerlo y aĂșn mĂĄs emocionante, subidos a una bestia de metal con cuatro ruedas: un cuatrimoto. Admirar las grandes praderas rurales que el gran Valle del Sagrado ofrece y las que alguna vez el Inca contemplĂł, pero con la dosis de adrenalina que sus cuerpos necesitan. visitarĂĄn el sitio arqueolĂłgico de Moray, denominado como un posible laboratorio de investigaciĂłn agrĂ­cola incaico, donde observarĂĄn la particular distribuciĂłn de sus andenes y los microclimas que se han replicado en ellos. Luego conocerĂĄn las salineras de Maras, una mina de sal explotada desde la Ă©poca incaica y cuyo origen sigue siendo un misterio. ÂĄAtrĂ©vete a recorrer el camino inca como un explorador aguerrido y deja que el mĂ­stico Cusco te deslumbre!');
