INSERT INTO `pcta_postmeta` VALUES (606,85,'descripcion','âRetiros Espirituales con Ayahuasca en Cusco, PerĂșâ, durante cuatro dĂ­as. Los Retiros Espirituales se basan en una serie de conocimientos y tĂ©cnicas chamĂĄnicas ancestrales que tienen la finalidad de despertar el poder de la curaciĂłn interior. Los participantes tendrĂĄn la oportunidad de conocer y experimentar las bondades de la medicina tradicional andina y amazĂłnica, especialmente de la planta madre Ayahuasca; de esta manera, iniciarĂĄn su camino personal hacia la armonĂ­a, la curaciĂłn fĂ­sica, espiritual, mental y emocional.');
