INSERT INTO `pcta_postmeta` VALUES (621,86,'descripcion','La Planta Maestra San Pedro o Wachuma es la conexiĂłn del hombre con la madre tierra (Pachamama) y el universo, con esta ceremonia nosotros nos reconectamos con algo con lo que nacimos, con nuestra esencia divina perteneciente a la madre tierra que muchas veces permanece dormida en nuestro interior y que con solo una intenciĂłn la podemos volver a despertar.  Las ceremonias se realizan en lugares sagrados de los incas. Es considerada por los descendientes de los antiguos pueblos originarios de AmĂ©rica la Planta Maestra, que era utilizada en la antigĂŒedad para la limpieza y purificaciĂłn del cuerpo, la mente y el espĂ­ritu');
