INSERT INTO `pcta_postmeta` VALUES (695,92,'descripcion','Cusco es la ciudad continuamente habitada mĂĄs antigua en SudamĂ©rica, la capital arqueolĂłgica de AmĂ©rica y la ciudad mĂĄs cosmopolita en PerĂș. EstĂĄ plagada de contrastes, no solo en sus estructuras sino en todo respecto a ella; su cultura, sus celebraciones, su comida, las personas que viven en ella, etc.; acĂĄ podrĂĄ encontrar personas de todo el mundo.');
