INSERT INTO `pcta_postmeta` VALUES (971,114,'descripcion','El Camino Inca a Machupicchu estĂĄ catalogado como una de las mejores caminatas en todo el mundo por lo exquisito de su belleza y maravillosos alrededores naturales, es una experiencia espectacular que hay que realizar a menos una vez en la vida. Tiene un recorrido de 42 km desde el km 82 hasta la Ciudadela de Machu Picchu. Personas de todo el mundo vienen a PerĂș para realizarlo.');
