INSERT INTO `pcta_postmeta` VALUES (1121,126,'descripcion','Realice una excursiĂłn de medio dĂ­a por la conocida Ciudad de los Reyes del PerĂș, Lima. En este tour podrĂĄ conocer los sitios mĂĄs histĂłricos, aquellos que poseen una bella arquitectura colonial, hermosos templos e iglesias, barrios residenciales, admirables paisajes alrededor del mar y demĂĄs atractivos turĂ­sticos de la capital peruana. Disfrute de este atractivo tanto en la maĂ±ana como en la tarde.');
