INSERT INTO `pcta_postmeta` VALUES (1145,128,'descripcion','La comunidad de los Uros habita pequeĂ±as islas sobre el Lago Titicaca y lo han hecho durante cientos de aĂ±os por el habitante tuvo que aprender a cosechar la totora, para luego juntarlas en grandes cantidades, unirlas por la raĂ­z y asĂ­ dar forma a sus pequeĂ±as islas como si fueran plataformas. Estos pobladores tambiĂ©n son conocidos como los hijos de la mama cocha que significa madre lago, pues tienen que mantener sus islas diariamente, agregando nuevas capas de âTotoraâ (planta del lago), asimismo sus hogares y sus botes estĂĄn hechos de esa misma planta.');
