INSERT INTO `pcta_postmeta` VALUES (1170,130,'descripcion','Para conocer las maravillosas Islas de Uros y la isla natural de Taquile ubicadas a la altitud de 3812 msnm. ÂĄEs en esta Ășltima donde conocerĂĄs su magnĂ­fica playa (lugar Ășnico de la isla de Taquile) con arena blanca y con vistas esplĂ©ndidas hacia los nevados de la Cordillera de los Andes!\r\nAdemĂĄs de estos bellos paisajes, gozarĂĄs de la maravillosa experiencia de compartir la esencia del hombre andino junto con las familias locales.\r\nUna placentera experiencia que te dejarĂĄ hermosos recuerdos de las islas que te harĂĄn desear volver.\r\n');
