INSERT INTO `pcta_postmeta` VALUES (1196,132,'descripcion','Dentro del lago mayor del Titicaca, habitan pueblos de hombres y mujeres solidarios que comparten su cultura, y sus tradiciones ancestrales. El viajero tiene la sensaciĂłn de haber dado un salto en el tiempo, para revivir un pedazo de la grandiosa historia de los hijos del Sol. Estos nativos son grandes navegantes y maestros del tejido que preservan su sabidurĂ­a en los diseĂ±os y decoraciĂłn de su vestimenta y en sus tradiciones. La isla es tambiĂ©n de gran valor paisajĂ­stico por su ubicaciĂłn en la inmensidad del lago.\r\nEste viaje es muy popular por la oportunidad de interactuar con los nativos que aĂșn mantienen su inocencia de mente y corazĂłn, debido al estilo de vida muy simple y tranquila que llevan. Las viviendas son muy sencillas y acogedoras, todas con vista al Lago, esta combinaciĂłn de cultura y naturaleza hace de este lugar un encanto.');
