INSERT INTO `pcta_postmeta` VALUES (1221,134,'descripcion','La Reserva Nacional de Tambopata se encuentra en la cuenca del rĂ­o Tambopata que cubre el sur del rĂ­o Madre de Dios RegiĂłn (40% de la reserva), asĂ­ como Puno RegiĂłn (60% de la reserva)! \r\nSu rica biodiversidad incluye 103 especies de mamĂ­feros, 1.300 especies de mariposas, ÂĄ90 especies de anfibios y 41 familias de ĂĄrboles que contienen 165 especies de ĂĄrboles! La reserva tiene una superficie de 274.690 hectĂĄreas. El clima es cĂĄlido y hĂșmedo con alta precipitaciĂłn anual.\r\nDurante este recorrido, visitamos los dos mĂĄs grandes de arcilla-licks de la AmazonĂ­a peruana: ÂĄÂĄChuncho y Colorado!! Ambos estĂĄn situados en la Zona Reservada de la Reserva Nacional Tambopata. El Colorado collpa se coloca en el banco del lado derecho del rĂ­o Tambopata, mientras que el Chuncho es en el banco del lado izquierdo. Los arcilla-lame Chuncho y Colorado atraen un gran nĂșmero de guacamayos, loros, pericos, ÂĄÂĄasĂ­ como otros tipos de animales cada dĂ­a!\r\n');
