INSERT INTO `pcta_postmeta` VALUES (1346,144,'descripcion','Experimenta Puerto Maldonado como todo un aventurero, anĂ­mate a explorar su hermosa selva y conocer su exquisita biodiversidad. TendrĂĄ la oportunidad de vivir la magia de nuestra selva amazĂłnica que estĂĄ dentro de la Reserva Nacional Tambopata, (278,000 mil hectĂĄreas protegidas), aprecia la belleza del lago Sandoval y navega sus aguas en un bote a remos y descubre tu lado extremo haciendo Canopy a una altura de 30 metros, desde donde podrĂĄs disfrutar de la hermosa vista panorĂĄmica de la densa selva tropical.');
