INSERT INTO `pcta_postmeta` VALUES (1521,158,'descripcion','Este tour de aventura te ofrece la oportunidad de subir y disfrutar en la famosa duna mĂĄs alta del mundo. Cerro blanco con mĂĄs de 2090 msnm. que forma parte de las montaĂ±as andinas. \r\nRealizaremos una caminata por un agradable sendero y travesando hermosos paisajes. Una vez en la cima. podrĂĄs disfrutar de una vista paisajista en todo su esplendor de los valles de Nazca e impresionantes dunas formados por el capricho de la naturaleza. \r\nDonde podrĂĄs practicar el deporte de sandboard sobre inmensas dunas de arena que le harĂĄn disfrutar y experimentar una extrema adrenalina acompaĂ±ado por nuestros experimentados guĂ­as.\r\n');
