INSERT INTO `pcta_postmeta` VALUES (1596,164,'descripcion','Nuestro programa lo invita a visitar y disfrutar lo mejor de la costa sur de PerĂș, explorando el desierto con sus enigmĂĄticas lĂ­neas de Nazca, disfrutando de sus dunas y Oasis donde tendrĂĄ la experiencia de practicar deportes de aventura como sandboarding o paseos en dunas. AdemĂĄs de visitar hermosos paisajes naturales de la Reserva Natural de Paracas privilegiada con una riqueza Ășnica de vida marina.');
