INSERT INTO `pcta_postmeta` VALUES (1700,181,'descripcion','Tour Reserva Nacional de Paracas nos harĂĄ disfrutar no solo de fabulosos paisajes marĂ­timos y desĂ©rticos, sino tambiĂ©n podremos aprender sobre el antiguo hombre Paracas, quien habito estas zona hace mĂĄs de 2000 aĂ±os, dejando como evidencia en sus necrĂłpolis una gran diversidad de bellos tejidos, los cuales asombran al mundo moderno.\r\nEn la PenĂ­nsula de Paracas tambiĂ©n es posible disfrutar de un baĂ±o relajante en una de sus bellas playas o simplemente hacer caminatas alrededor de ellas en busca de fotografĂ­as.\r\n');
