INSERT INTO `pcta_postmeta` VALUES (1789,198,'descripcion','La cultura Nazca fue una civilizaciĂłn que pudo dominar este desierto tan ĂĄrido gracias al desarrollo de una obra de ingenierĂ­a hidrĂĄulica, construidas en diferentes partes de valle fueron hechos con piedras lajas, canto rodado y troncos de Huarango para poder captar las aguas subterrĂĄneas. Uno de los que mejores se conservan son lo Acueductos de Cantalloc.');
