INSERT INTO `pcta_postmeta` VALUES (1804,200,'descripcion','Los mejores vinos y piscos, el misterio de un pueblo y los encantos de un oasis en el desierto te esperan, inicia el dĂ­a degustando los mejores vinos y piscos de Ica ÂĄSiĂ©ntete un experto catador!\r\nAnĂ­mate a conocer los secretos de la ciudad, ÂĄAprovecha la oportunidad para comprar los mejores recuerdos para los tuyos!, el Oasis de la Huacachina te espera, recorre el centro artesanal y llega hasta la Laguna, pasea, compra artesanĂ­a o anĂ­mate a practicar alguna actividad extrema, termina el dĂ­a dejĂĄndote envolver por las historias de brujas y maldiciones en el Pueblo de Cachiche.\r\n');
