INSERT INTO `pcta_postmeta` VALUES (1857,210,'descripcion','Las collpas de guacamayos es la formaciĂłn arcillosa del por acciĂłn del rio y estĂĄ ubicado en el barranco de los rĂ­os. Todas las maĂ±anas al amanecer los guacamayos, entre otras aves se dirigen a este lugar para ingerir por 30 minutos aprox. La razĂłn por el cual estas aves consumen arcilla es por segĂșn los investigadores dicen que contiene sales vitales y minerales utilizadas en la dieta de los animales quienes consumen. Esta excursiĂłn es para todos sin excepciĂłn alguna, donde podrĂĄ vivir la emociĂłn de sentir y escuchar la belleza del encanto de la naturaleza, en el transcurso de su estadĂ­a apreciarĂĄ la fauna y bastante vegetaciĂłn.');
