INSERT INTO `pcta_postmeta` VALUES (1912,221,'descripcion','El tour comprende una visita plena de experiencias a los dos mĂĄs importantes atractivos de la regiĂłn: la impresionante Colpa de Guacamayos en el Parque Nacional Bahuaja-Sonene y el paradisĂ­aco Lago Sandoval en la Zona Reservada Tambopata-Candamo, ademĂĄs de posibles encuentros con animales silvestres. Un tour reservado para los amantes de la naturaleza, especial para los aficionados a la observaciĂłn de aves y vida silvestre.');
