INSERT INTO `pcta_postmeta` VALUES (1935,227,'descripcion','Es el corazĂłn de la Reserva de biosfera, es una de las ĂĄreas protegidas mĂĄs importantes en el trĂłpico sudamericano localizado en el franco oriental de las montaĂ±as andinas. El Parque Nacional del Manu protege una secuencia de paisaje natural intacta que desciende de los 4.200 mt. Hacia la extensa selva lluviosa en la zona amazĂłnica.\r\nEl Manu es el refugio de muchas especies de animales en peligro de extinciĂłn, que incluye al jaguar, caimĂĄn negro, nutria giganta, ĂĄguila arpĂ­a, etc. La Reserva del Manu hoy considerado el Ășnico hogar en la tierra con una gran biodiversidad de flora y fauna silvestre. El Manu alberga un promedio de 860 especies de aves que incluye 7 especies de coloridos papagayos, 84 especies de mamĂ­feros que incluyen 13 especies de monos y miles de especies de insectos y plantas.\r\n');
