INSERT INTO `pcta_postmeta` VALUES (1952,230,'descripcion','La zona cultural del Manu es una de las tres zonas del Parque Nacional del Manu que cubre las altas montaĂ±as, bosque mesĂłfilo de montaĂ±a y la selva baja. En esta zona hay pequeĂ±os pueblos, los colonos y comunidades originarias que trabajan en actividades productivas como la agricultura y la madera a baja escala, ya que estas actividades son controladas por el Ministerio de Agricultura y autoridades del Parque Nacional del Manu (SERNANP). La Zona Cultural del Manu cuenta con un bosque nublado que en la actualidad es una de las zonas del mundo donde la fauna silvestre todavĂ­a vive en abundancia en su habita natural donde existen 8.000 especies de plantas, mĂĄs de 400 especies de aves y 10 especies de mamĂ­feros han sido identificadas en el bosque nublado del Manu. ');
