INSERT INTO `pcta_postmeta` VALUES (1969,233,'descripcion','El lago Sandoval es uno de los lagos mĂĄs bellos del PerĂș; un gran cuerpo de agua protegido en la Reserva Nacional Tambopata. Es el hogar de una familia de nutrias gigantes en peligro de extinciĂłn, pero tenemos una excelente oportunidad de verlos durante nuestra estancia. Las orillas del lago estĂĄn pobladas por selvas inundadas de Mauritia, que son el hogar de monos de seis especies diferentes, asĂ­ como con una gran variedad de pĂĄjaros coloridos. Esta visita a la Reserva Nacional Tambopata nos permite observar el Lago Sandoval y el ĂĄrea circundante donde veremos una gran cantidad de vida silvestre en la reserva y aprender sobre la selva amazĂłnica.');
