INSERT INTO `pcta_postmeta` VALUES (2179,272,'descripcion','El camino Inca corto combina hermosos paisajes de montaĂ±a y vistas panorĂĄmicas increĂ­bles, exuberante bosque nublado, una selva subtropical del esplĂ©ndido entorno natural, con el magnĂ­fico trabajo de los Incas como una mezcla excepcional de pavimento de piedras colocados sobre el camino, la agricultura, terrazas, fuentes de agua, tĂșneles y sitios arqueolĂłgicos sorprendentes como la famosa Puerta del Sol y de la puesta de sol sobre Machu Picchu. Esta caminata es ideal para aquellos que tienen tiempo limitado y aquellos que quieran tener una caminata fĂĄcil de lograr.');
