INSERT INTO `pcta_postmeta` VALUES (2221,283,'descripcion','El Valle Sagrado de los Incas, en los Andes peruanos, estĂĄ compuesto por numerosos rĂ­os que descienden por quebradas y pequeĂ±os valles; posee numerosos monumentos arqueolĂłgicos y pueblos indĂ­genas.\r\nEste valle fue muy apreciado por los incas debido a sus especiales cualidades geogrĂĄficas y climĂĄticas. Fue uno de los principales puntos de producciĂłn por la riqueza de sus tierras y lugar en donde se produce el mejor grano de maĂ­z en el PerĂș.\r\n');
