INSERT INTO `pcta_postmeta` VALUES (2338,303,'descripcion','Visitar Machupicchu constituye una experiencia inolvidable, lo mĂ­stico que desprenden sus imponentes muros pĂ©treos, inspiran un profundo respeto por los constructores de esta monumental obra, quienes supieron conjugar, como nadie en el mundo. La ciudad Inka de Machupicchu, estĂĄ ubicado en medio de majestuosas montaĂ±as de ceja de selva su incomparable belleza y fuerza espiritual es privilegiada, la ciudad escondida dentro del trĂłpico y construida con una localizaciĂłn geogrĂĄfica privilegiada que combina con las montaĂ±as sagradas, agua corriente y un alineamiento celestial casi perfecto, un excelente trabajo en piedra y un gran nĂșmero de terrazas para la agricultura, es impresionante.');
