INSERT INTO `pcta_postmeta` VALUES (2359,307,'descripcion','Ofrenda a la pachamama es una ceremonia o tambiĂ©n conocida como âPago a la Tierraâ son rituales de origen ancestral, cuya finalidad es devolver a la tierra todo lo que nos ha dado. Estas ceremonias de ofrenda a la pachamama se realizan comĂșnmente el primer dĂ­a de agosto, pero se pueden realizar cualquier dĂ­a del AĂ±o.\r\nDentro de esta Ceremonia de ofrenda a la pachamama, para pedir nuestros mĂĄs anhelados deseos para nuestra vida, lo que soĂ±amos para nuestro futuro y lo que queremos para nuestros seres queridos. Todo esto basado en una conexiĂłn entre el mundo material y el espiritual.\r\n');
