INSERT INTO `pcta_postmeta` VALUES (3659,507,'descripcion','ÂĄSentirĂĄ como si estarĂ­a volando! A travĂ©s del vuelo en la tirolesa, el participante tendrĂĄ la oportunidad de apreciar las diversas montaĂ±as y paraĂ­sos andinos, el Valle Sagrado de los Incas y la animada cultura de la comunidad Racchi. DespuĂ©s de la tirolesa, manejaremos durante 20 minutos para llegar a Chinchero. AquĂ­ podremos admirar las paredes incaicas bien conservadas de la plaza principal, asĂ­ como los muchos altares. TambiĂ©n visitaremos la hermosa iglesia colonial, Ășnica por sus ilustraciones e imĂĄgenes interiores.');
