INSERT INTO `pcta_postmeta` VALUES (3883,527,'descripcion','Esta es una ruta alternativa al clĂĄsico Camino Inca a Machu Picchu, que lo llevarĂĄ a travĂ©s de paisajes increĂ­bles y belleza natural con flora y fauna de la regiĂłn. La caminata incluirĂĄ cruzar valles y montaĂ±as antes de llegar a la \"Ciudad Perdida de los Incas\", Machu Picchu.\r\nConectando la ciudad de Mollepata, Cusco con Machu Picchu, el Salkantay Trek es un antiguo y remoto sendero ubicado en la misma regiĂłn que el Camino Inca donde enormes montaĂ±as nevadas chocan con exuberantes selvas tropicales.');
