INSERT INTO `pcta_postmeta` VALUES (4856,620,'descripcion','En la visita a este importante atractivo turĂ­stico podremos apreciar muchos monumentos arqueolĂłgicos de la Ă©poca Inca, rĂ­os importantes del Cusco y pueblos andinos. El valle ha sido apreciado desde la antigĂŒedad por los incas gracias a la geografĂ­a y el clima de la zona. Fue considerado como uno de los principales lugares de producciĂłn por sus fĂ©rtiles tierras donde se realiza la producciĂłn del mejor maĂ­z en el PerĂș.');
