INSERT INTO `pcta_postmeta` VALUES (4880,622,'descripcion','Llamada tambiĂ©n MontaĂ±a de Siete Colores, MontaĂ±a ArcoĂ­ris o MontaĂ±a de Colores (los pobladores le llaman Cerro Colorado), es una montaĂ±a del PerĂș con una altitud de 5.200 msnm.\r\nEstĂĄ situada en el camino al nevado Ausangate, en los Andes del PerĂș, RegiĂłn Cusco, entre los distritos de Cusipata, provincia de Quispicanchi, y Pitumarca, provincia de Canchis.');
