INSERT INTO `pcta_postmeta` VALUES (5267,680,'descripcion','Machu Picchu Full Day, viaje de un dĂ­a hacia una de las obras maestras de la IngenierĂ­a Civil y Arquitectura del Imperio Inca, construido en el corazĂłn de la ceja selva bajo la protecciĂłn de las montaĂ±as sagradas Huayna Picchu y Machu Picchu.\r\nLa ciudad Inca de Machu Picchu te estĂĄ esperando, ten la experiencia Ășnica y mĂĄgica visitando a esta Maravilla del Mundo y Patrimonio Mixta Cultural y Natural de la Humanidad.');
