INSERT INTO `pcta_posts` VALUES (27,1,'2020-03-06 18:50:03','2020-03-06 18:50:03','a:11:{s:10:\"aria-label\";s:0:\"\";s:4:\"type\";s:7:\"wysiwyg\";s:12:\"instructions\";s:0:\"\";s:8:\"required\";i:0;s:17:\"conditional_logic\";i:0;s:7:\"wrapper\";a:3:{s:5:\"width\";s:0:\"\";s:5:\"class\";s:0:\"\";s:2:\"id\";s:0:\"\";}s:13:\"default_value\";s:373:\"Planeta acogedor espacio turĂ­stico, que marcara tu vida de inicio a fin hasta el retorno a tu planeta. Este lugar es una maravilla del mundo, conoce cada rincĂłn de su misterioso y acogedor espacio turĂ­stico, que marcara tu vida de inicio a fin hasta el retorno a tu planeta, acogedor espacio turĂ­stico, que marcara tu vida de inicio a fin hasta el retorno a tu planeta.\";s:4:\"tabs\";s:3:\"all\";s:7:\"toolbar\";s:4:\"full\";s:12:\"media_upload\";i:1;s:5:\"delay\";i:0;}','DescripciĂłn del Tour','descripcion','publish','closed','closed','','field_5e629af417021','','','2023-04-15 22:18:51','2023-04-15 22:18:51','',25,'https://peruconexiontravel.com/?post_type=acf-field&#038;p=27',0,'acf-field','',0);
