INSERT INTO `pcta_posts` VALUES (181,1,'2020-05-03 18:25:29','2020-05-03 18:25:29','[tabby title=\"Itinerario\"]\r\n<h2>DĂ­a 1:Â Paracas</h2>\r\n11:00 a.m.Â A la hora indicada abordaremos nuestra movilidad que compartirĂĄ con otros clientes para iniciar la excursiĂłn al impresionante Desierto Costero de la Reserva Nacional de Paracas, visitaremos el centro de InterpretaciĂłn de la reserva, el cual ofrece interesantes cuadros y fotos mostrando toda la vida y fauna que en ella existe. TambiĂ©n haremos un recorrido por la PenĂ­nsula de Paracas, observando el desierto colorido rojizo, amarillo, formaciones hechas por los vientos y visitando, sus bellas playas, tales como playa Yumaque, playa Roja yÂ playa Lagunillas, en esta playa tendrĂĄn tiempo libre para que puedan almorzar ya que hay restaurantes frente a la playa, o hacer caminatas alrededor de la playa en busca de fotos, luego retornaremos a Paracas.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>RecepciĂłn en la estaciĂłn de bus o en elÂ hotel seleccionado</li>\r\n 	<li>GuĂ­a profesional bilingĂŒe</li>\r\n 	<li>Transporte</li>\r\n 	<li>Asistencia permanente</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li>Almuerzo</li>\r\n 	<li>Propinas</li>\r\n 	<li>Taza turĂ­stica ministerio de Ambiente USD 5.00</li>\r\n</ul>\r\n[tabbyending]','Tour Reserva Nacional de Paracas','','inherit','closed','closed','','166-revision-v1','','','2020-05-03 18:25:29','2020-05-03 18:25:29','',166,'https://peruconexiontravel.com/2020/05/03/166-revision-v1/',0,'revision','',0);
