INSERT INTO `pcta_posts` VALUES (192,1,'2020-05-04 03:25:26','2020-05-04 03:25:26','[tabby title=\"Itinerario\"]\r\n<h2>DĂ­a 1:Â Nazca</h2>\r\nDisfrute de un vuelo excitante sobre las LĂ­neas de Nazca, el cual ofrece una oportunidad espectacular para ver 12 de las mundialmente famosas LĂ­neas de Nazca, incluyendo el colibrĂ­, el perro, las manos, el astronauta, el ĂĄrbol, la araĂ±a, la ballena, la lagartija, el tiburĂłn y mucho mĂĄs.\r\n\r\nLo recogeremos en su hotel en Nazca o en la estaciĂłn de bus. SerĂĄ transportado al Aeropuerto MarĂ­a Reiche, a 10 minutos de distancia del centro de Nazca. En el aeropuerto lo ayudaremos con los procedimientos de registro y entrada, tales como el pago de su impuesto de aeropuerto, pasar por seguridad y el pesaje. Luego podrĂĄ ver un breve documental acerca del descubrimiento de las LĂ­neas de Nazca. DespuĂ©s, lo asistiremos en su entrada al aeroplano Cessna 206.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Recogida en su hotel o la estaciĂłn de bus</li>\r\n 	<li>Traslado al aeropuerto</li>\r\n 	<li>VĂ­deo documental acerca de las LĂ­neas de Nazca</li>\r\n 	<li>Un asiento abordo de una aeronave Cessna</li>\r\n 	<li>Transporte de regreso a su hotel</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li>Impuesto de aeropuerto ($10 USD por persona)</li>\r\n 	<li>propinas</li>\r\n</ul>\r\n[tabbyending]','Sobrevuelo LĂ­neas de Nazca','','inherit','closed','closed','','160-revision-v1','','','2020-05-04 03:25:26','2020-05-04 03:25:26','',160,'https://peruconexiontravel.com/2020/05/04/160-revision-v1/',0,'revision','',0);
