INSERT INTO `pcta_posts` VALUES (200,1,'2020-05-04 03:31:21','2020-05-04 03:31:21','[tabby title=\"Itinerario\"]\r\n<h2>DĂ­a 1: Ica</h2>\r\nHora de inicio del tour: 1:00 p.m.\r\n\r\nPunto de Encuentro:Â Recojo en hotel o EstaciĂłn de Buses\r\n\r\nEl tour te permitirĂĄ conocer bodegas vitivinĂ­colas artesanales, en las cuales podrĂĄs degustar vinos y piscos de gran calidad.\r\n\r\nPartida con Destino a la Huacachina y el centro artesanal. Se darĂĄn 2 horas libres, oportunidad para comprar artesanĂ­as (libre), o practicar alguna actividad en el desierto como sandboard (no incluido) o paseos en tubulares (no incluido) o realizar paseos en bote por la laguna (no incluido)\r\n\r\nPartida con destino a Cachiche. Conoce la historia de sus brujas y sus antiguas leyendas.\r\n\r\n6:30 p.m.Â Fin del tour.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Recojo en hoteles ubicadosÂ en el centro de la ciudadÂ y estaciĂłn de buses.</li>\r\n 	<li>DegustaciĂłn de Vinos y Piscos.</li>\r\n 	<li>Visita a Bodegas VitivinĂ­colas.</li>\r\n 	<li>Paseo por la Ciudad.</li>\r\n 	<li>Visita a la Huacachina.</li>\r\n 	<li>Transporte TurĂ­stico.</li>\r\n 	<li>GuĂ­a de Turismo.</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li></li>\r\n 	<li>Paseos en Tubulares.</li>\r\n 	<li>Comidas ni Bebidas.</li>\r\n 	<li>NingĂșn otro punto no establecido en el tour.</li>\r\n</ul>\r\n[tabbyending]','City Tour Ica','','inherit','closed','closed','','154-revision-v1','','','2020-05-04 03:31:21','2020-05-04 03:31:21','',154,'https://peruconexiontravel.com/2020/05/04/154-revision-v1/',0,'revision','',0);
