INSERT INTO `pcta_posts` VALUES (204,1,'2020-05-04 03:35:39','2020-05-04 03:35:39','[tabby title=\"Itinerario\"]\r\n\r\nEsta aventura comprende la visita a la Laguna de Huacachina y el paseo por las dunas y/o mĂ©danos del desierto a bordo de los Buggies o Tubulares que son vehĂ­culos con tracciĂłn 4 x 4 especialmente preparados para hacer este recorrido y conducidos por pilotos expertos. Esta actividad de Full Adrenalina se complementa con la prĂĄctica de la tabla sobre\r\n\r\narena conocida tambiĂ©n como SANDBOARDING. Se recomienda el turno de la tarde ya que podrĂĄn apreciar la puesta de sol en el desierto.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Itinerario</h2>\r\n<ul>\r\n 	<li>Recojo del Hotel en Ica y Traslado a Huacachina</li>\r\n 	<li>Paseo en Buggies + Sandboarding</li>\r\n 	<li>Retorno al Hotel en Ica</li>\r\n 	<li>DuraciĂłn: 01 hora aproximadamente</li>\r\n</ul>\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Traslado en vehĂ­culo turĂ­stico</li>\r\n 	<li>Instructor Sandboarding</li>\r\n 	<li>Ticket Buggies</li>\r\n</ul>\r\n* Servicio en Compartido o en Privado a elecciĂłn Consultar el Tarifario.\r\n\r\n[tabbyending]','Buggies y Sandboard Huacachina','','inherit','closed','closed','','152-revision-v1','','','2020-05-04 03:35:39','2020-05-04 03:35:39','',152,'https://peruconexiontravel.com/2020/05/04/152-revision-v1/',0,'revision','',0);
