INSERT INTO `pcta_posts` VALUES (248,1,'2020-05-04 04:10:05','2020-05-04 04:10:05','[tabby title=\"Itinerario\"]\r\n<h2>Atractivos que visitaremos</h2>\r\n<ul>\r\n 	<li>La Huaca Pucllana, centro ceremonial inca del siglo IV D.C.</li>\r\n 	<li>Centro HistĂłrico de Lima, con una variedad inigualable de edificios coloniales y paisajes urbanos de hace 400 aĂ±os atrĂĄs.</li>\r\n 	<li>El Museo del Banco Central de Reserva, donde podrĂĄ apreciar una colecciĂłn privada de artĂ­culos de la Ă©poca pre colombina.</li>\r\n 	<li>Las Catacumbas del Templo de San Francisco. Criptas con muestras de arte religioso.</li>\r\n 	<li>Plaza San Martin, una de las plazas mĂĄs importantes de la Ciudad de los Reyes.</li>\r\n 	<li>Plaza de Armas de Lima, con vista a los edificios de la Municipalidad de Lima y la Catedral.</li>\r\n 	<li>Larcomar, un centro de diversiĂłn con tiendas, restaurantes, cines, ĂĄreas verdes y una incomparable vista del mar peruano.</li>\r\n</ul>\r\n<strong>Nota:</strong> Este itinerario puede ser realizado en la maĂ±ana o en la tarde.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2><strong>Incluye</strong></h2>\r\n<ul>\r\n 	<li>GuĂ­a profesional de turismo en espaĂ±ol / inglĂ©s</li>\r\n 	<li>Traslados en Bus turĂ­stico</li>\r\n 	<li>Tickets de ingreso (entradas) a todos los lugares de visita</li>\r\n 	<li>Asistencia constante durante el tour</li>\r\n</ul>\r\n<h2><strong>No incluye</strong></h2>\r\n<ul>\r\n 	<li>Alimentos no mencionados en el paquete</li>\r\n 	<li>Gastos extra</li>\r\n 	<li>Alojamiento</li>\r\n</ul>\r\n[tabbyending]','City Tour en Lima','','inherit','closed','closed','','126-revision-v1','','','2020-05-04 04:10:05','2020-05-04 04:10:05','',126,'https://peruconexiontravel.com/2020/05/04/126-revision-v1/',0,'revision','',0);
