INSERT INTO `pcta_posts` VALUES (292,1,'2020-05-04 05:02:21','2020-05-04 05:02:21','[tabby title=\"Itinerario\"]\r\n<h2>DĂ­a 1: Cusco - Maras</h2>\r\n<ol>\r\n 	<li><strong> . Moray:</strong> Nuestra visita termina visitando las terrazas circulares de Moray,Â las cuales son una muestra de cĂłmo el hombre andino desafĂ­o a la naturaleza y aprovecharon su medio geogrĂĄfico para utilizarlo en su beneficio, estos andenes circulares sirvieron de laboratorio agrĂ­cola que permitiĂł obtener una gran variedad de especies de papa, maĂ­z, entre otros productos.</li>\r\n 	<li><strong> Maras:</strong> El poblado de Maras serĂĄ nuestro primer punto de visita; el cual fue de gran importancia durante el Virreinato, declarado Villa de San Francisco de AsĂ­s (fue el principal abastecedor de sal de la sierra meridional), asĂ­ lo demuestran la iglesia y las casonas que aĂșn conservan los escudos de nobleza indĂ­gena en sus fachadas.</li>\r\n 	<li><strong> Salineras de Maras:</strong> Las Salineras de Maras nuestro segundo punto de visita pertenece al poblado Maras, el cual fue de gran importancia durante el Virreinato, fue el principal abastecedor de sal de la sierra meridional, asĂ­ lo demuestran la iglesia y las casonas que aĂșn conservan los escudos de nobleza indĂ­gena en sus fachadas. Las Minas de sal de Maras sorprenden al visitante por los mĂĄs de tres mil pozos que presenta y que en la actualidad siguen siendo trabajados por mĂĄs de 360 familias, quienes han heredado esta costumbre y labor extractiva artesanal; la comercializaciĂłn de la sal se encuentra a cargo de la asociaciĂłn Maras Sal, encargada de velar por intereses de la comunidad desde finales de los aĂ±os 80.</li>\r\n</ol>\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Transporte</li>\r\n 	<li>GuĂ­a profesional bilingĂŒe</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li>AlimentaciĂłn</li>\r\n 	<li>BTP (boleto turĂ­stico parcial)</li>\r\n</ul>\r\n[tabbyending]','Tour Maras Moray y Salineras','','inherit','closed','closed','','102-revision-v1','','','2020-05-04 05:02:21','2020-05-04 05:02:21','',102,'https://peruconexiontravel.com/2020/05/04/102-revision-v1/',0,'revision','',0);
