INSERT INTO `pcta_posts` VALUES (323,1,'2020-05-04 17:03:25','2020-05-04 17:03:25','[tabby title=\"Itinerario\"]\r\n<h2>DĂ­a 1: Cusco - Valle Sagrado</h2>\r\nA las 09: 00 am pasaremos a recogerlos de sus respectivos hoteles. Seguidamente partiremos hacia el rĂ­o Urubamba en el Sagrado Valle de los Incas (Norte de Cusco), donde nuestra guĂ­a darĂĄ una charla introductoria sobre la seguridad y el uso del equipo para comenzar nuestra aventura por el Urubamba. Nos transportaremos en balsa por alrededor de 2 horas y Âœ en los rĂĄpidos de II, III. IV+ y V, dependiendo la ruta que seleccionemos. Podremos llegar a correr en Huambutio hasta clase II, Ollantaytambo Clase III (Nosotros lo ejecutamos de mayo a diciembre), Quiquijana Class III (Diciembre a Mayo) y Chuquicahuana en Clase III, IV y V (de Diciembre a mayo) para este Ășltimo, ese es el mĂĄs difĂ­cil, asĂ­ que por nuestra seguridad tomamos un kayac, que significa una guĂ­a extra simplemente para la seguridad.\r\n\r\nHora de llegada a Cusco a las 17: 00 horas.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>GuĂ­as especializados en rafting.</li>\r\n 	<li>Todo el equipo de Rafting (casco, Chaleco de seguridad, bote y remo, wetsuit)</li>\r\n 	<li>Transporte</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li>Alimentos</li>\r\n</ul>\r\n[tabbyending]','Rafting RĂ­o Urubamba','','inherit','closed','closed','','80-revision-v1','','','2020-05-04 17:03:25','2020-05-04 17:03:25','',80,'https://peruconexiontravel.com/2020/05/04/80-revision-v1/',0,'revision','',0);
