INSERT INTO `pcta_posts` VALUES (365,1,'2020-05-12 14:37:35','2020-05-12 14:37:35','[div class=\"BoxNos\"]\r\n\r\n[div class=\"BoxItem\"]\r\n<h2>PERĂ CONEXION TRAVEL AGENCY</h2>\r\nSomos una agencia de viajes especializada en turĂ­smo en el perĂș.DiseĂ±amos y organizamos programas turĂ­sticos para viajeros.Individuales,Grupales,corporaciones,,grupo de familias,Agencias de viajes,etc.De todo el mundo.\r\n\r\nBrindamos asesorĂ­a personalizada a nuestros clientes viajeros, para cumplir plenamente lo que ofrecemos.\r\n\r\nPor lo cual realizamos con nuestro equipo profecional. toures privadas y grupales con entuciasmo y eficiencia.\r\n\r\nOfrecemos y operamos en todo el territorio peruano,para realizar las actividades turĂ­sticos de la mejor calidad. Para poder llegar hacia la satisfaccion de nuestros clientes viajeros de todo el mundo.\r\n\r\n[end-div]\r\n\r\n[div class=\"BoxItemImg\"]\r\n\r\n<img class=\"alignnone wp-image-261 size-full\" src=\"https://peruconexiontravel.com/wp-content/uploads/2020/03/incajungle.jpg\" alt=\"\" width=\"876\" height=\"493\" />\r\n\r\n[end-div]\r\n\r\n[end-div]','Nosotros','','publish','closed','closed','','nosotros','','','2020-05-12 14:37:35','2020-05-12 14:37:35','',0,'https://peruconexiontravel.com/?page_id=365',0,'page','',0);
INSERT INTO `pcta_posts` VALUES (361,1,'2020-05-12 14:26:21','2020-05-12 14:26:21','<div class=\"FormularioPage\">\r\n[text* Nombre placeholder \"Nombre\"]\r\n[email* Correo placeholder \"Correo\"]\r\n[tel* Telefono placeholder \"Telefono\"]\r\n[date fecha placeholder \"Fecha\"]\r\n[textarea Comentario placeholder \"Comentario\"]\r\n[submit \"Enviar\"]\r\n</div>\n1\nÂ«ReservaÂ» - Peru Conexion Travel Agecy\nPeru Conexion Travel Agecy <reservas@peruconexiontravel.com>\nreservas@peruconexiontravel.com\n<table style=\"font-family:Arial\" border=\"1\" cellpadding=\"5\" cellspacing=\"0\">\r\n<tr bgcolor=\"#f8f8f8\"><th colspan=\"2\">Solicitar InformaciĂłn</th></tr>\r\n<tr bgcolor=\"#ffffff\"><td>Nombre: </td><td>[Nombre]</td></tr>\r\n<tr bgcolor=\"#ffffff\"><td>Correo: </td><td>[Correo]</td></tr>\r\n<tr bgcolor=\"#ffffff\"><td>Telefono: </td><td>[Telefono]</td></tr>\r\n<tr bgcolor=\"#ffffff\"><td>Fecha: </td><td>[fecha]</td></tr>\r\n<tr bgcolor=\"#f8f8f8\"><td>Mensaje: </td><td>[Comentario]</td></tr>\r\n</table>\r\n\r\n-- \r\nEste mensaje se ha enviado desde un formulario de contacto en Peru Conexion Travel Agecy\n\n\n1\n\n\nPeru Conexion Travel Agecy Â«[your-subject]Â»\nPeru Conexion Travel Agecy <wordpress@skynetcusco.com>\n[your-email]\nCuerpo del mensaje:\r\n[your-message]\r\n\r\n-- \r\nEste mensaje se ha enviado desde un formulario de contacto en Peru Conexion Travel Agecy (https://skynetcusco.com/clientes/conexion)\nReply-To: gonzalo1998eri@gmail.com\n\n\n\nGracias por tu mensaje. Ha sido enviado.\nHubo un error intentando enviar tu mensaje. Por favor intĂ©ntalo de nuevo mĂĄs tarde.\nUno o mĂĄs campos tienen un error. Por favor revisa e intĂ©ntalo de nuevo.\nHubo un error intentando enviar tu mensaje. Por favor intĂ©ntalo de nuevo mĂĄs tarde.\nDebes aceptar los tĂ©rminos y condiciones antes de enviar tu mensaje.\nEl campo es obligatorio.\nEl campo es demasiado largo.\nEl campo es demasiado corto.\nHubo un error desconocido subiendo el archivo.\nNo tienes permisos para subir archivos de este tipo.\nEl archivo es demasiado grande.\nSe ha producido un error subiendo la imagen\nEl formato de fecha es incorrecto.\nLa fecha es anterior a la mĂĄs temprana permitida.\nLa fecha es posterior a la mĂĄs tardĂ­a permitida.\nEl formato de nĂșmero no es vĂĄlido.\nEl nĂșmero es menor que el mĂ­nimo permitido.\nEl nĂșmero es mayor que el mĂĄximo permitido.\nLa respuesta al cuestionario no es correcta.\nLa direcciĂłn de correo electrĂłnico que has introducido no es vĂĄlida.\nLa URL no es vĂĄlida.\nEl nĂșmero de telĂ©fono no es vĂĄlido.','FormPage','','publish','closed','closed','','formpage','','','2023-04-18 20:36:00','2023-04-18 20:36:00','',0,'https://peruconexiontravel.com/?post_type=wpcf7_contact_form&#038;p=361',0,'wpcf7_contact_form','',0);
