INSERT INTO `pcta_posts` VALUES (366,1,'2020-05-12 14:37:35','2020-05-12 14:37:35','[div class=\"BoxNos\"]\r\n\r\n[div class=\"BoxItem\"]\r\n<h2>PERĂ CONEXION TRAVEL AGENCY</h2>\r\nSomos una agencia de viajes especializada en turĂ­smo en el perĂș.DiseĂ±amos y organizamos programas turĂ­sticos para viajeros.Individuales,Grupales,corporaciones,,grupo de familias,Agencias de viajes,etc.De todo el mundo.\r\n\r\nBrindamos asesorĂ­a personalizada a nuestros clientes viajeros, para cumplir plenamente lo que ofrecemos.\r\n\r\nPor lo cual realizamos con nuestro equipo profecional. toures privadas y grupales con entuciasmo y eficiencia.\r\n\r\nOfrecemos y operamos en todo el territorio peruano,para realizar las actividades turĂ­sticos de la mejor calidad. Para poder llegar hacia la satisfaccion de nuestros clientes viajeros de todo el mundo.\r\n\r\n[end-div]\r\n\r\n[div class=\"BoxItemImg\"]\r\n\r\n<img class=\"alignnone wp-image-261 size-full\" src=\"https://peruconexiontravel.com/wp-content/uploads/2020/03/incajungle.jpg\" alt=\"\" width=\"876\" height=\"493\" />\r\n\r\n[end-div]\r\n\r\n[end-div]','Nosotros','','inherit','closed','closed','','365-revision-v1','','','2020-05-12 14:37:35','2020-05-12 14:37:35','',365,'https://peruconexiontravel.com/365-revision-v1',0,'revision','',0);
INSERT INTO `pcta_posts` VALUES (369,1,'2020-05-14 15:19:05','2020-05-14 15:19:05','<h2><img class=\"wp-image-371 alignright\" src=\"https://peruconexiontravel.com/wp-content/uploads/2020/05/90052151_538492580138821_3270325910728737757_n-e1589470025685.jpg\" alt=\"\" width=\"297\" height=\"371\" />MISION</h2>\r\nPERĂ CONEXION TRAVEL AGENCY.Ofrece la mejor experiencia y calidad Ășnica,para cada uno de sus clientes viajeros,a travĂ©s de los mejores recursos de PERĂ CONEXION TRAVEL AGENCY.Parques arqueolĂłgicos y atractivos naturales.\r\n<h2>VISION</h2>\r\nDe PERĂ CONEXION TRAVEL AGENCY. Es ser el lĂ­der indiscutible en el turĂ­smo y la industria y ser una de las empresas mĂĄs competitivas y admiradas en PerĂș e internacional.\r\n<h2>FILOSOFIA</h2>\r\n<strong>PERU CONEXION TRAVEL</strong>.Tiene la filosofia orientada a la mejora continua y una preocupaciĂłn constante.Por brindar la mejor calidad de servisio en todos los tours realizados, con nuestra empresa;Para cada uno de nuestros clientes viajeros nacionales y extrangeros.\r\n<h2>NUESTROS VALORES</h2>\r\n<h3>EL RESPETO</h3>\r\nEN PERĂ CONEXIĂN TRAVEL AGENCY.Tenemos la capacidad de reconocer,apreciar y valorar con Amor, a nuestros clientes y en general a quienes nos rodea.Porque teniendo en cuenta que todos somos Ășnicos y valiosas.\r\n<h3>LA HONESTIDAD</h3>\r\nPERĂ CONEXIĂN TRAVEL AGENCY.Te ofrece los tours y las Excursiones en PerĂș con.Honestidad,transparencia,sinceros,justos, confiables y\"con la Verdad\".\r\n<h3>LA RESPONSABILIDAD</h3>\r\nLA EMPRESA DE PERĂ CONEXIĂN TRAVEL AGENCY.Actuamos y asumimos nuestros compromisos, desde el principio hasta el final de las excursiones,ofrecidas de nuestra empresa.\r\n<h3>LA LIBERTAD</h3>\r\nPERĂ CONEXIĂN TRAVEL AGENCY.Le dĂĄ la facultad y la libertad a todos sus clientes. De decidir y asignar sus excursiones en lo ofrecido de nuestra empresa.\r\n\r\nPOR QUĂ ELEGIR CON \"PERĂ CONEXION TRAVEL AGENCY\"\r\n\r\nPor Experiencia profesionalismo, sĂłmos un Equipo de muchas cualidades y sabiduria.Para dar la mejor satisfacciĂłn, experiencia y la felicidad a sĂșs clientes.','Nuestra MisiĂłn','','publish','closed','closed','','nuestra-mision','','','2020-05-14 15:30:22','2020-05-14 15:30:22','',0,'https://peruconexiontravel.com/?page_id=369',0,'page','',0);
