INSERT INTO `pcta_posts` VALUES (467,1,'2020-08-15 00:12:54','2020-08-15 00:12:54','TOUR SALKANTAY TREKKING\r\n\r\n- Â <a href=\"https://peruconexiontravel.com/\">El Nevado de Salkantay</a>, es uno de las montaĂ±as mĂĄs elevadas de la regiĂłn del Cusco, junto con el nevado de Ausangate en la cordillera de Vilcanota la cual estĂĄ situada mĂĄs al sur.\r\n\r\n&nbsp;\r\n\r\nNo obstante, es considerada la mĂĄs grandiosa en su esplĂ©ndido aislamiento y la grandeza de su esplendor . Es ademĂĄs una de las montaĂ±as de la regiĂłn andina que presentan mayores problemas tĂ©cnicos, en todas sus vertientes, para la escalada deportiva.\r\n\r\nLa cumbre del Salcantay presenta dos cimas, la Este y la OesteAntiguamente la Oeste, mĂĄs esbelta y atractiva que la Este era ligeramente mĂĄs elevada al estar coronada por un serac. Tras el paso de los aĂ±os y el derrumbe de este serac, como constato el prestigioso Pireneista Louis Audoubert, la altura es prĂĄcticamente idĂ©ntica en ambas cimas.','TOUR A SALKANTAY TREKKING','','inherit','closed','closed','','457-revision-v1','','','2020-08-15 00:12:54','2020-08-15 00:12:54','',457,'https://peruconexiontravel.com/457-revision-v1',0,'revision','',0);
