INSERT INTO `pcta_posts` VALUES (713,1,'2023-05-15 20:25:08','2023-05-15 20:25:08','TOUR VALLE SAGRADO DE LOS INCAS\n\n-El Valle Sagrado de los Incas, en los Andes peruanos, estĂĄ compuesto por numerosos rĂ­os que descienden por quebradas y pequeĂ±os valles; posee numerosos monumentos arqueolĂłgicos y pueblos indĂ­genas que son: centro arqueolĂłgico de Pisac, pueblo colonial de Pisac,urubanba,centro arqueolĂłgico de ollantaytambo.\n\nEl Valle Sagrado abarca un tramo del rĂ­o Urubamba, que serpentea a travĂ©s de montaĂ±as escarpadas y valles fĂ©rtiles. La combinaciĂłn de suelo fĂ©rtil y un clima favorable hizo de esta regiĂłn un lugar estratĂ©gico para la agricultura y un centro econĂłmico importante para los incas. AdemĂĄs, los incas consideraban que el valle tenĂ­a una energĂ­a especial y lo consideraban un lugar sagrado.\n\nEn el Valle Sagrado, se pueden encontrar diversos sitios arqueolĂłgicos y ruinas incas, muchos de los cuales estĂĄn abiertos al pĂșblico. Algunos de los sitios mĂĄs conocidos incluyen:\n<ol>\n 	<li>Pisac: Ubicado en la cima de una montaĂ±a, Pisac es conocido por su impresionante complejo arqueolĂłgico y su mercado artesanal.</li>\n 	<li>Ollantaytambo: Es un antiguo pueblo inca y una fortaleza ceremonial. Tiene una arquitectura impresionante y ofrece vistas panorĂĄmicas del valle.</li>\n 	<li>Moray: Es un conjunto de terrazas circulares escalonadas que los incas utilizaban con fines agrĂ­colas y experimentales.</li>\n 	<li>Chinchero: Un pueblo tradicional con una iglesia colonial construida sobre los cimientos de una antigua construcciĂłn inca.</li>\n</ol>','TOUR VALLE SAGRADO DE LOS INCAS','','inherit','closed','closed','','423-autosave-v1','','','2023-05-15 20:25:08','2023-05-15 20:25:08','',423,'https://peruconexiontravel.com/?p=713',0,'revision','',0);
INSERT INTO `pcta_posts` VALUES (714,1,'2023-05-15 20:16:54','2023-05-15 20:16:54','TOUR VALLE SAGRADO DE LOS INCAS\r\n\r\n-El Valle Sagrado de los Incas, en los Andes peruanos, estĂĄ compuesto por numerosos rĂ­os que descienden por quebradas y pequeĂ±os valles; posee numerosos monumentos arqueolĂłgicos y pueblos indĂ­genas que son: centro arqueolĂłgico de Pisac, pueblo colonial de Pisac,urubanba,centro arqueolĂłgico de ollantaytambo .\r\n\r\nEl Valle Sagrado abarca un tramo del rĂ­o Urubamba, que serpentea a travĂ©s de montaĂ±as escarpadas y valles fĂ©rtiles. La combinaciĂłn de suelo fĂ©rtil y un clima favorable hizo de esta regiĂłn un lugar estratĂ©gico para la agricultura y un centro econĂłmico importante para los incas. AdemĂĄs, los incas consideraban que el valle tenĂ­a una energĂ­a especial y lo consideraban un lugar sagrado.\r\n\r\nEn el Valle Sagrado, se pueden encontrar diversos sitios arqueolĂłgicos y ruinas incas, muchos de los cuales estĂĄn abiertos al pĂșblico. Algunos de los sitios mĂĄs conocidos incluyen:\r\n<ol>\r\n 	<li>Pisac: Ubicado en la cima de una montaĂ±a, Pisac es conocido por su impresionante complejo arqueolĂłgico y su mercado artesanal.</li>\r\n 	<li>Ollantaytambo: Es un antiguo pueblo inca y una fortaleza ceremonial. Tiene una arquitectura impresionante y ofrece vistas panorĂĄmicas del valle.</li>\r\n 	<li>Moray: Es un conjunto de terrazas circulares escalonadas que los incas utilizaban con fines agrĂ­colas y experimentales.</li>\r\n 	<li>Chinchero: Un pueblo tradicional con una iglesia colonial construida sobre los cimientos de una antigua construcciĂłn inca.</li>\r\n</ol>','TOUR VALLE SAGRADO DE LOS INCAS','','inherit','closed','closed','','423-revision-v1','','','2023-05-15 20:16:54','2023-05-15 20:16:54','',423,'https://peruconexiontravel.com/?p=714',0,'revision','',0);
