INSERT INTO `pcta_posts` VALUES (742,1,'2023-05-18 19:57:43','2023-05-18 19:57:43','[tabby title=\"Itinerario\"]\n<h2>DĂ­a 1: Arequipa</h2>\nSe recoge de su hotel para empezar el recorrido por uno de los miradores mĂĄs atractivos de la ciudad llamado \"Carmen Alto\" en este lugar observaremos los tresÂ volcanes tutelares que rodean a la ciudad de Arequipa, terrazas pre-incas y nuestro guĂ­a nos hablarĂĄ de la agricultura de Arequipa.\n\nSeguidamente nos trasladamos hacia el distrito de Yanahuara para apreciar los Portales de Yanahuara construido en Sillar y la Iglesia de San Juan Bautista.\n\nLuego nos dirigiremos al Monasterio de Santa Catalina que presenta una ciudadela de sillar, este monasterio fue fundado en el aĂ±o de 1579, luego nos dirigiremos hacia la BasĂ­lica Menor de Arequipa, que estĂĄ ubicada en la Plaza de Armas, con un estilo NeoclĂĄsico; finalizando el recorrido nos trasladaremos a la Iglesia de la CompaĂ±Ă­a de JesĂșs y a la CĂșpula de San Ignacio que es una de las que mejor estado de conservaciĂłn presenta en la ciudad de Arequipa.\n\n[tabby title=\"Incluyen\"]\n<h2>Incluye</h2>\n<ul>\n 	<li>Transporte turĂ­stico grupal</li>\n 	<li>GuĂ­a personal bilingĂŒe</li>\n</ul>\n<h2>No incluye</h2>\n<ul>\n 	<li>Ingreso monasterio santa catalina USD 15.00</li>\n 	<li>Catedral U$D 5.00</li>\n 	<li>CĂșpula de san Ignacio U$D 2.00</li>\n</ul>\n[tabbyending]','City Tour Arequipa','','inherit','closed','closed','','66-autosave-v1','','','2023-05-18 19:57:43','2023-05-18 19:57:43','',66,'https://peruconexiontravel.com/?p=742',0,'revision','',0);
INSERT INTO `pcta_posts` VALUES (743,1,'2023-05-18 20:15:13','2023-05-18 20:15:13','[tabby title=\"Itinerario\"]\r\n<h2>DĂ­a 1: Arequipa</h2>\r\nSe recoge de su hotel para empezar el recorrido por uno de los miradores mĂĄs atractivos de la ciudad llamado \"Carmen Alto\" en este lugar observaremos los tresÂ volcanes tutelares que rodean a la ciudad de Arequipa, terrazas pre-incas y nuestro guĂ­a nos hablarĂĄ de la agricultura de Arequipa.\r\n\r\nSeguidamente nos trasladamos hacia el distrito de Yanahuara para apreciar los Portales de Yanahuara construido en Sillar y la Iglesia de San Juan Bautista.\r\n\r\nLuego nos dirigiremos al Monasterio de Santa Catalina que presenta una ciudadela de sillar, este monasterio fue fundado en el aĂ±o de 1579, luego nos dirigiremos hacia la BasĂ­lica Menor de Arequipa, que estĂĄ ubicada en la Plaza de Armas, con un estilo NeoclĂĄsico; finalizando el recorrido nos trasladaremos a la Iglesia de la CompaĂ±Ă­a de JesĂșs y a la CĂșpula de San Ignacio que es una de las que mejor estado de conservaciĂłn presenta en la ciudad de Arequipa.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Transporte turĂ­stico grupal</li>\r\n 	<li>GuĂ­a personal bilingĂŒe</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li>Ingreso monasterio santa catalina USD 15.00</li>\r\n 	<li>Catedral U$D 5.00</li>\r\n 	<li>CĂșpula de san Ignacio U$D 2.00</li>\r\n</ul>\r\n[tabbyending]','City Tour Arequipa','','inherit','closed','closed','','66-revision-v1','','','2023-05-18 20:15:13','2023-05-18 20:15:13','',66,'https://peruconexiontravel.com/?p=743',0,'revision','',0);
