INSERT INTO `pcta_posts` VALUES (759,1,'2023-05-19 00:04:10','2023-05-19 00:04:10','<div class=\"flex-1 overflow-hidden\">\r\n<div class=\"react-scroll-to-bottom--css-jdfmc-79elbk h-full dark:bg-gray-800\">\r\n<div class=\"react-scroll-to-bottom--css-jdfmc-1n7m0yu\">\r\n<div class=\"flex flex-col items-center text-sm dark:bg-gray-800\">\r\n<div class=\"group w-full text-gray-800 dark:text-gray-100 border-b border-black/10 dark:border-gray-900/50 bg-gray-50 dark:bg-[#444654]\">\r\n<div class=\"flex p-4 gap-4 text-base md:gap-6 md:max-w-2xl lg:max-w-xl xl:max-w-3xl md:py-6 lg:px-0 m-auto\">\r\n<div class=\"relative flex w-[calc(100%-50px)] flex-col gap-1 md:gap-3 lg:w-[calc(100%-115px)]\">\r\n<div class=\"flex flex-grow flex-col gap-3\">\r\n<div class=\"min-h-[20px] flex flex-col items-start gap-4 whitespace-pre-wrap break-words\">\r\n<div class=\"markdown prose w-full break-words dark:prose-invert light\"></div>\r\n</div>\r\n</div>\r\n<div class=\"flex justify-between lg:block\">\r\n<h2 class=\"text-gray-400 flex self-end lg:self-center justify-center mt-2 gap-2 md:gap-3 lg:gap-1 lg:absolute lg:top-0 lg:translate-x-full lg:right-0 lg:mt-0 lg:pl-2 visible\">CITY TOUR CUSCO</h2>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"absolute bottom-0 left-0 w-full border-t md:border-t-0 dark:border-white/20 md:border-transparent md:dark:border-transparent md:bg-vert-light-gradient bg-white dark:bg-gray-800 md:!bg-transparent dark:md:bg-vert-dark-gradient pt-2\"><form class=\"stretch mx-2 flex flex-row gap-3 last:mb-2 md:mx-4 md:last:mb-6 lg:mx-auto lg:max-w-2xl xl:max-w-3xl\">\r\n<div class=\"relative flex h-full flex-1 items-stretch md:flex-col\">\r\n<div class=\"\">\r\n<div class=\"h-full flex ml-1 md:w-full md:m-auto md:mb-2 gap-0 md:gap-2 justify-center\">\r\n\r\nEl <a href=\"https://peruconexiontravel.com/\">City tour de Cusco</a> es una actividad turĂ­stica popular que te permite explorar y descubrir los principales atractivos de la ciudad de Cusco, ubicada en PerĂș. Cusco es conocida como la antigua capital del Imperio Inca y tiene una rica historia y patrimonio cultural.\r\n\r\nDurante el City tour, generalmente se visitan varios lugares emblemĂĄticos dentro y cerca de la ciudad. Estos son algunos de los sitios que comĂșnmente se incluyen en el recorrido:\r\n<h2>QORICANCHA</h2>\r\n<ol>\r\n 	<li>QoricanchaTemplo del Sol: Es uno de los lugares mĂĄs sagrados del Imperio Inca y se encuentra en el centro de la ciudad de Cusco. Fue un importante templo dedicado al culto del Sol y sus muros estaban recubiertos de oro. Actualmente, se puede apreciar la combinaciĂłn de la arquitectura incaica y colonial en el Convento de Santo Domingo, que se construyĂł sobre el antiguo templo</li>\r\n</ol>\r\nSACSAYHUAMAN\r\n<ol>\r\n 	<li>SacsayhuamĂĄn: Es una imponente fortaleza inca ubicada en las afueras de Cusco. Se caracteriza por sus enormes piedras talladas y su impresionante arquitectura. Desde lo alto de <a href=\"https://peruconexiontravel.com/\">SacsayhuamĂĄn</a>, se puede disfrutar de una vista panorĂĄmica espectacular de Cusco y sus alrededores</li>\r\n</ol>\r\n</div>\r\n<div class=\"h-full flex ml-1 md:w-full md:m-auto md:mb-2 gap-0 md:gap-2 justify-center\">\r\n\r\nQ\'enqo, Puka Pukara y Tambomachay: Estos son otros sitios arqueolĂłgicos importantes que suelen formar parte del city tour. Q\'enqo es un complejo rocoso donde se realizaron rituales incas, Puka Pukara es una fortaleza militar y Tambomachay es un sitio ceremonial que cuenta con fuentes de agua\r\n\r\n</div>\r\n&nbsp;\r\n<div class=\"h-full flex ml-1 md:w-full md:m-auto md:mb-2 gap-0 md:gap-2 justify-center\">\r\n\r\nEl City tour de <a href=\"https://peruconexiontravel.com/\">Cusco</a> suele ser una excelente manera de conocer la riqueza histĂłrica y cultural de la ciudad. Es recomendable realizarlo con un guĂ­a turĂ­stico que pueda brindar informaciĂłn detallada sobre cada sitio visitado y su significado histĂłrico. AdemĂĄs, recuerda llevar ropa cĂłmoda, protector solar, agua y una cĂĄmara fotogrĂĄfica para capturar los hermosos paisajes y monumentos a lo largo del recorrido.\r\n\r\n</div>\r\n</div>\r\n</div>\r\n</form></div>','CITY TOUR CUSCO','','inherit','closed','closed','','745-revision-v1','','','2023-05-19 00:04:10','2023-05-19 00:04:10','',745,'https://peruconexiontravel.com/?p=759',0,'revision','',0);
INSERT INTO `pcta_posts` VALUES (762,1,'2023-05-22 22:42:30','2023-05-22 22:42:30','<h2><a href=\"https://peruconexiontravel.com/city-tour-cusco/\">CITY TOUR CUSCO</a></h2>\nThe <a href=\"https://peruconexiontravel.com/city-tour-cusco/\">City Tour of Cusco</a> is a popular tourist activity that allows you to explore and discover the main attractions of the city of Cusco, located in Peru. Cusco is known as the ancient capital of the Inca Empire and has a rich history and cultural heritage.\nDuring the City Tour, several emblematic places within and near the city are usually visited. These are some of the sites commonly included in the tour:\n\n<img class=\"alignnone size-medium wp-image-593\" src=\"https://peruconexiontravel.com/wp-content/uploads/2020/11/templodelsol-300x139.png\" alt=\"\" width=\"300\" height=\"139\" />\n<h2>QORICANCHA</h2>\nQoricancha Temple of the Sun: It is one of the most sacred places of the Inca Empire and is located in the center of the city of Cusco. It was an important temple dedicated to the worship of the Sun, and its walls were covered in gold. Currently, you can appreciate the combination of Inca and colonial architecture in the Santo Domingo Convent, which was built on top of the ancient temple.\n<h2>SACSAYHUAMAN</h2>\nSacsayhuamĂĄn: It is an imposing Inca fortress located on the outskirts of Cusco. It is characterized by its enormous carved stones and impressive architecture. From the top of SacsayhuamĂĄn, you can enjoy a spectacular panoramic view of Cusco and its surroundings.\nQ\'enqo, Puka Pukara, and Tambomachay: These are other important archaeological sites that are often part of the city tour. Q\'enqo is a rocky complex where Inca rituals were performed, Puka Pukara is a military fortress, and Tambomachay is a ceremonial site with water fountains.\n\nThe City Tour of Cusco is usually an excellent way to get to know the historical and cultural richness of the city. It is recommended to do it with a tour guide who can provide detailed information about each visited site and its historical significance. Also, remember to wear comfortable clothing, sunscreen, bring water, and a camera to capture the beautiful landscapes and monuments along the tour.','CITY TOUR CUSCO','','inherit','closed','closed','','745-autosave-v1','','','2023-05-22 22:42:30','2023-05-22 22:42:30','',745,'https://peruconexiontravel.com/?p=762',0,'revision','',0);
INSERT INTO `pcta_posts` VALUES (764,1,'2023-05-22 22:37:25','2023-05-22 22:37:25','<h2><a href=\"https://peruconexiontravel.com/city-tour-cusco/\">CITY TOUR CUSCO</a></h2>\r\nEl <a href=\"https://peruconexiontravel.com/city-tour-cusco/\">City tour de Cusco</a> es una actividad turĂ­stica popular que te permite explorar y descubrir los principales atractivos de la ciudad de Cusco, ubicada en PerĂș. Cusco es conocida como la antigua capital del Imperio Inca y tiene una rica historia y patrimonio cultural.\r\n\r\nDurante el City tour, generalmente se visitan varios lugares emblemĂĄticos dentro y cerca de la ciudad. Estos son algunos de los sitios que comĂșnmente se incluyen en el recorrido:\r\n\r\n<img class=\"alignnone size-medium wp-image-593\" src=\"https://peruconexiontravel.com/wp-content/uploads/2020/11/templodelsol-300x139.png\" alt=\"\" width=\"300\" height=\"139\" />\r\n\r\n&nbsp;\r\n<h2>QORICANCHA</h2>\r\nQoricancha Templo del Sol: Es uno de los lugares mĂĄs sagrados del Imperio Inca y se encuentra en el centro de la ciudad de Cusco. Fue un importante templo dedicado al culto del Sol y sus muros estaban recubiertos de oro. Actualmente, se puede apreciar la combinaciĂłn de la arquitectura incaica y colonial en el Convento de Santo Domingo, que se construyĂł sobre el antiguo templo\r\n<h2>SACSAYHUAMAN</h2>\r\nSacsayhuamĂĄn: Es una imponente fortaleza inca ubicada en las afueras de Cusco. Se caracteriza por sus enormes piedras talladas y su impresionante arquitectura. Desde lo alto de SacsayhuamĂĄn, se puede disfrutar de una vista panorĂĄmica espectacular de Cusco y sus alrededores\r\n\r\nQ\'enqo, Puka Pukara y Tambomachay: Estos son otros sitios arqueolĂłgicos importantes que suelen formar parte del city tour. Q\'enqo es un complejo rocoso donde se realizaron rituales incas, Puka Pukara es una fortaleza militar y Tambomachay es un sitio ceremonial que cuenta con fuentes de agua\r\n\r\nEl City tour de Cusco suele ser una excelente manera de conocer la riqueza histĂłrica y cultural de la ciudad. Es recomendable realizarlo con un guĂ­a turĂ­stico que pueda brindar informaciĂłn detallada sobre cada sitio visitado y su significado histĂłrico. AdemĂĄs, recuerda llevar ropa cĂłmoda, protector solar, agua y una cĂĄmara fotogrĂĄfica para capturar los hermosos paisajes y monumentos a lo largo del recorrido.','CITY TOUR CUSCO','','inherit','closed','closed','','745-revision-v1','','','2023-05-22 22:37:25','2023-05-22 22:37:25','',745,'https://peruconexiontravel.com/?p=764',0,'revision','',0);
