INSERT INTO `pcta_trustindex_tripadvisor_reviews` VALUES (1,'Felipe d','https://media-cdn.tripadvisor.com/media/photo-o/1a/f6/e4/a9/default-avatar-2020-50.jpg','<strong>Muito recomendado!</strong>\nNeymar nos ajudou criando um roteiro para vĂĄrios dias, com tudo incluso, roteiro, guias, transporte e por um preĂ§o bom. Recomendo a todos !Os guias tambĂ©m foram muito bons: Guido, Willian, Jimmy, Edgar',5.0,NULL,'2023-04-08',0);
INSERT INTO `pcta_trustindex_tripadvisor_reviews` VALUES (2,'Guilherme Rufo','https://media-cdn.tripadvisor.com/media/photo-o/28/c1/98/18/guilherme-r.jpg','<strong>Amazing experience from the airport until the last day in Cusco</strong>\nI was in Cusco with 7 other friends. And we couldn\'t have chose the other travel agency. Peru Conexion made our experience awesome abroad. They has the best tour guides with the best deal possible.We visited Rainbow Mountain, laguna Humantay, museums, the city, salineras de mara and so many other places with them.I highly recommend them for your trip!',5.0,NULL,'2023-04-08',0);
INSERT INTO `pcta_trustindex_tripadvisor_reviews` VALUES (3,'Nivia A','https://media-cdn.tripadvisor.com/media/photo-f/01/2e/70/a4/avatar075.jpg','<strong>Rainbow đ Mountain â°ïž Absolutely Amazing! Peru Conexion Travel Agency is the way to go!</strong>\nPeru Conexion Travel Agency made everything so easy and enjoyable! They are so professional, prompt, courteous, very knowledgeable and they always go above and beyond to help you. They literally take care of everything for you to enjoy.In route you have the best advice, explanations and history. Breakfast and lunch were delicious and the most important the support from the tour guide (in our case Edgar) to make it to the top is unparalleled.You will not regret it if you choose Peru Conexion Travel Agency, if I could give them 10 stars â­ïž I would!',5.0,NULL,'2023-03-13',0);
INSERT INTO `pcta_trustindex_tripadvisor_reviews` VALUES (4,'mario fernando c','https://media-cdn.tripadvisor.com/media/photo-o/1a/f6/eb/a3/default-avatar-2020-38.jpg','<strong>Amazing</strong>\nUna excelente agencia de viajes, muy puntuales, atentos y siempre pendientes de nosotros.Muy correctos en su negocio.',5.0,NULL,'2022-10-17',0);
INSERT INTO `pcta_trustindex_tripadvisor_reviews` VALUES (5,'Shirley C','https://media-cdn.tripadvisor.com/media/photo-o/1a/f6/ed/00/default-avatar-2020-4.jpg','<strong>Amazing experience</strong>\nExcelente agencia, cumplieron a cabalidad con todo lo que ofrecieron, muy amables en el servicio, el tour a la Laguna Humantay fue genial!!',5.0,NULL,'2022-08-29',0);
INSERT INTO `pcta_trustindex_tripadvisor_reviews` VALUES (6,'Patricia V','https://media-cdn.tripadvisor.com/media/photo-o/1a/f6/e9/ef/default-avatar-2020-66.jpg','<strong>Hermosa experiencia !!!!</strong>\nMuy buenos toursÂĄÂĄÂĄ Cumplen al 100%. Jilmar (Neymar) siempre estuvo atento y nos brindo un excelente servicio.',5.0,NULL,'2022-07-08',0);
INSERT INTO `pcta_trustindex_tripadvisor_reviews` VALUES (7,'Sergio Z','https://media-cdn.tripadvisor.com/media/photo-s/15/95/9c/89/sergio-m.jpg','<strong>Excelente y honesto servicio turĂ­stico.</strong>\nExcelente servicio de trasporte privado y turĂ­stico, ademĂĄs cuentan con diferentes tours a los sitios de mayor interĂ©s, Ă©l conductor muy amable y formal, asĂ­ como honesto. Nosotros hicimos varios tours con Ă©l/ellos durante nuestra estancia. Excelente servicio. Machupicchu, MontaĂ±a de Colores, City Tour y traslados al hotel - aeropuerto 100% recomendable con Ă©l (Jilmar/)ellos. Te ayudan a comprar boletos de tren y entradas a los sitos turĂ­sticos. Saludos y buen viaje.',5.0,NULL,'2022-07-08',0);
INSERT INTO `pcta_trustindex_tripadvisor_reviews` VALUES (8,'tanya p','https://media-cdn.tripadvisor.com/media/photo-o/1a/f6/f4/20/default-avatar-2020-31.jpg','<strong>Excelente trato!!</strong>\nGilmar nos tratĂł excelente, fue muy atento, siempre se mantuvo en comunicaciĂłn con nosotros, nos dio el mejor trato y los tours estuvieron muy completos, a tiempo todo.',5.0,NULL,'2022-07-08',0);
INSERT INTO `pcta_trustindex_tripadvisor_reviews` VALUES (9,'Catalina LeĂłn','https://media-cdn.tripadvisor.com/media/photo-s/1b/a6/de/81/avatar.jpg','<strong>Gracias a ellos logramos conocer Machu Pichu</strong>\nEl taxista que nos dio servicio del aeropuerto resultĂł ser de esta Empresa. De camino conversamos y nos ofreciĂł ayudarnos con el viaje a MachuPichu. Nos llevĂł a la oficina y logramos organizar el viaje para el domingo. Se nos recogiĂł en el hotel a la hora indicada y todo saliĂł a la perfecciĂłn con los servicios bimodales y el guĂ­a!',4.0,NULL,'2022-06-15',0);
INSERT INTO `pcta_trustindex_tripadvisor_reviews` VALUES (10,'Diego G','https://media-cdn.tripadvisor.com/media/photo-o/1a/f6/ea/2e/default-avatar-2020-67.jpg','<strong>Una excelente aventura</strong>\nJilmar presta un excelente servicio, recomiendo la agencia y contactarlos, preguntar por el.Durante nuestra estadio en Cuzco sĂșper recomendado ir a Laguna Umantay allĂ­ nuestro guĂ­a fue Marco una persona que se tomĂł el tiempo de explicarnos la cultura y costumbres de las personas que habitan cerca a esta.',5.0,NULL,'2022-04-16',0);
